							    	query.append(" SELECT user_name as VALUE, MEMBER_TYPE as CONST,PHONE_NO as CONTACTNO FROM LHS_USER_DTLS where CARD_NO='"+cardNo.trim()+"' and MEMBER_TYPE='"+patientVo.getTypeDirAisFlag()+"' and ACTIVE_YN='Y' and STATUS='A' ");
							    	submitList = genericDao.executeSQLQueryList(LabelBean.class, query.toString());
