	@Override
	public String getAyushName(String ayushId) throws Exception {
		String AyushName="";
		String b=null;
		if(ayushId!=null && ayushId!="")
		{
			if(ayushId.contains("~"))
			{
				 ayushId= ayushId.replaceAll("~", "','");
			  
			}
			
		}
		StringBuffer query = new StringBuffer();
		query.append("SELECT package_name  as TEST FROM ais_packages where package_code in ('"+ayushId+"')   ");
		List<PreauthVO> ayushNameList = genericDao.executeSQLQueryList(PreauthVO.class, query.toString());
		if(ayushNameList!=null)
		{
			for(PreauthVO vo : ayushNameList)
			{
				if(vo.getTEST() !=null)
				{
					AyushName=AyushName+vo.getTEST()+",";
					
				}
			}
			AyushName=	AyushName.substring(0, AyushName.length()-1);
		}
		return AyushName;
	}
