					queryBuff.append("  ,p.regHospId as INTIID, hm.dispName||''||hm.dispCode as HOSPNAME , case when p.gender='M' then 'Male' else case when p.gender='F' then 'Female' else p.gender end end as GENDER , a.cmbDtlName as STATUS ,ec.caseStatus as CASESTAT   ");
