				queryBuff.append(" , p.age||' years '||p.ageMonths||' months '||p.ageDays||' days ' as AGE , cast(p.contactNo as string) as CONTACT , case when p.slab ='P' then 'Private Ward' else 'Semi Private Ward' end as slabType ");
