	/*
	 * Added by Srikalyan to get the Biometric Details 
	 * for corresponding Registered Patient
	 */
	@Override
	public boolean verifyPatientBiometrics(String patId ,String fingerPrint)
		{
			boolean result=false; 
			try
				{
					EhfPatientBioReg ehfPatientBioReg = genericDao.findById(EhfPatientBioReg.class, String.class,patId);
					if(ehfPatientBioReg!=null && fingerPrint !=null)
						{
							//Start for the Web Service Code
							String biomWebServURL=config.getString("BiomWebServURL");
							if(biomWebServURL!=null && !"".equalsIgnoreCase(biomWebServURL))
								{
									URL asriUrl=new URL(biomWebServURL);
									if(asriUrl!=null)
										{
											HttpURLConnection connectionObject=(HttpURLConnection)asriUrl.openConnection();
											if(connectionObject!=null)
												{
													connectionObject.setRequestMethod("GET");
													connectionObject.connect();
													int response = connectionObject.getResponseCode();
													if(response==200)
														{
															int timeOut=120000;//2Minutes
															AsriBiomServiceImplServiceStub webServiceStub=new AsriBiomServiceImplServiceStub(biomWebServURL);
															webServiceStub._getServiceClient().getOptions().setTimeOutInMilliSeconds(timeOut);
															AsriBiomServiceImplServiceStub.CompareBiometricValues requestObj=new CompareBiometricValues();
															requestObj.setLStrDBResult(ehfPatientBioReg.getFingerPrint());
															requestObj.setLStrNewFingerPrint(fingerPrint);
															AsriBiomServiceImplServiceStub.CompareBiometricValuesResponse responseObj = webServiceStub.compareBiometricValues(requestObj);
															if(responseObj!=null)
																{
																	boolean resultFromWeb=responseObj.getCompareBiometricValuesReturn();
																	result=resultFromWeb;
																}
														}
													connectionObject.disconnect();
												}
											else
												GLOGGER.error("Exception occured in verifyPatientBiometrics() method in PatientDaoImpl Class as Connection created using biomWebServURL is null");
										}
								}
							else
								GLOGGER.error("Exception occured in verifyPatientBiometrics() method in PatientDaoImpl Class as biomWebServURL from config is null ");
								
						
							//End for the Web Service Code
						}
				}
			catch(Exception e )
				{
					e.printStackTrace();
//					GLOGGER.error("Exception occured in verifyPatientBiometrics() method in PatientDaoImpl Class"+e.getMessage());
					return result;
				}
			return result;
		}
