	@Override
	public String getTokenNo(String hospId,String currentDate, String specialityType,String roomNo) 
	{
		StringBuffer query=new StringBuffer();
		List<LabelBean> tokenNos=null;
		String token="";
		try{
		query.append("select count(*) as COUNT from ehf_patient ep where ep.disp_code='"+hospId+"' and ep.speciality_type='"+specialityType+"'");
		query.append("  and ep.room_no='"+roomNo+"'  and TRUNC(ep.reg_hosp_date)= TO_DATE('"+currentDate+"','DD-MM-YYYY')");
		tokenNos=genericDao.executeSQLQueryList(LabelBean.class, query.toString());
		
		int tokenNo=0;
		if(tokenNos.get(0)!=null && tokenNos.get(0).getCOUNT()!=null )
		{
			token=String.valueOf(tokenNos.get(0).getCOUNT());
			tokenNo=Integer.parseInt(token);
			if(tokenNo==0)
			{
				tokenNo=1;
			}
			else 
			{
				tokenNo=tokenNo+1;
			}
			token=String.valueOf(tokenNo);
		}
		}
		catch(Exception e)
		{
			e.printStackTrace();
		}
		
		return token;
	}
	
