	@SuppressWarnings("unused")
	public int  updateRoomTokenNo(String dispId,String roleId,String userId)
	{
		StringBuffer query=new StringBuffer();
		StringBuffer query2=new StringBuffer();
		List<LabelBean> roomTokens=null;
		int tokenNo=0;

		try{
			query.append("select ep.tokenNo as tokenNo from EhfDispMedcoMpg ep");
			query.append(" where ep.id.dispId='"+dispId+"' and ep.id.grpId='"+roleId+"' and ep.id.medcoId='"+userId+"'");
			roomTokens=genericDao.executeHQLQueryList(LabelBean.class, query.toString());
			if(roomTokens!=null && roomTokens.get(0).getTokenNo()!=null)
			{
				tokenNo= Integer.parseInt(roomTokens.get(0).getTokenNo()) ;
				if(tokenNo==0)
				{
					tokenNo=1;
				}
				else
				{
					tokenNo=tokenNo+1;
				}
				
				EhfDispMedcoMpgId medcoMpgId=new EhfDispMedcoMpgId(dispId,roleId,userId);
				EhfDispMedcoMpg ehfdisp=genericDao.findById(EhfDispMedcoMpg.class, EhfDispMedcoMpgId.class, medcoMpgId);
				if(ehfdisp!=null)
				{
					ehfdisp.setTokenNo(String.valueOf(tokenNo));
				}
				
				genericDao.save(ehfdisp);
				
				
			}
		}
		catch(Exception e)
		{
			e.printStackTrace();
		}
		return tokenNo;
		
	}
	
