	@Override
	public List<LabelVO> retrieveLabelsData(
			HashMap<java.lang.String, Object> lMap) {
		// TODO Auto-generated method stub
		List<LabelVO> rsltList = new ArrayList<LabelVO>();
		StringBuffer sb = new StringBuffer();String[] args=null;
		if(lMap.get("combinedReport")!=null && lMap.get("combinedReport").toString().equalsIgnoreCase("Y"))
		{
			args = new String[1];
			args[0] = (String)lMap.get("patientId");
		}
		else{
			args = new String[2];
			args[0] = (String)lMap.get("patientId");
			args[1] = (String)lMap.get("investgtnId");
		}
//		args[1] = (String)lMap.get("investgtnId");
		try{
		sb.append("select rl.arrange_order as ARRANGEORDER,rl.sid SID,rl.report_name REPORTNAME,rl.field_type FIELDTYPE, da.field_data VALUEOFFIELD, to_char(rl.reference_interval) REFERENCEINTERVAL,rl.method METHOD,rl.investigation_name INVESTIGATIONNAME,da.investigation_id INVESTID");
		sb.append(" from ehf_lab_reports_data da, ehfm_oprtns_reports_labels rl where rl.sid = da.field_id(+) ");
		if(lMap.get("combinedReport")!=null && lMap.get("combinedReport").toString().equalsIgnoreCase("Y"))
		sb.append("and da.investigation_id is not null and da.patient_id(+) = ? order by da.investigation_id, cast(rl.arrange_order as number)");
		else
		sb.append(" and da.patient_id(+) = ? and rl.investigation_id(+) = ? order by cast(rl.arrange_order as number)");
		 rsltList = genericDao.executeSQLQueryList(LabelVO.class, sb.toString(), args);
		}
		catch(Exception e)
		{
			e.printStackTrace();
		}
		return rsltList;
	}
