	@Override
	public boolean checkAllSubmit(HashMap<java.lang.String, Object> lMap) {
		// TODO Auto-generated method stub
		boolean rslt = false;
		String patientId = (String)lMap.get("patientId");
		try
		{
			StringBuffer sb = new StringBuffer();
			String[] args = new String[2];
			args[0] = patientId;
			args[1] = patientId;
			sb.append(" select t.test_id VALUE from ehf_patient_tests t  where t.patient_id = ? minus select ls.investigation_id from ehf_lab_report_submit ls where ls.patient_id = ? ");
			List<LabelBean> submitList = genericDao.executeSQLQueryList(LabelBean.class, sb.toString(), args);
			if(submitList.size() > 0)
			{
				rslt=false;
			}
			else
				rslt = true;
			
			if(rslt)
			{
				EhfPatient ehfPatient = genericDao.findById(EhfPatient.class, String.class, patientId);
				if(ehfPatient != null)
				{
					ehfPatient.setDtrsFlag("");
					ehfPatient = genericDao.save(ehfPatient);
				}

				List<GenericDAOQueryCriteria> criteriaList = new ArrayList<GenericDAOQueryCriteria>(); 
				criteriaList.add(new GenericDAOQueryCriteria("casePatientNo",ehfPatient.getPatientId(),GenericDAOQueryCriteria.CriteriaOperator.EQUALS));
			    List<EhfCase> ehfCaseLst = genericDao.findAllByCriteria(EhfCase.class, criteriaList);
			    if(ehfCaseLst.size() > 0)
			    {
			    	EhfCase ehfCase = genericDao.findById(EhfCase.class, String.class, ehfCaseLst.get(0).getCaseId());
			    	if(ehfCase!=null)
			    	{
			    		ehfCase.setCaseStatus(config.getString("CASE.CaseDrafted"));
			    		ehfCase = genericDao.save(ehfCase);
			    	}
			    }
			}
		}
		catch(Exception e)
		{
			rslt = false;
			e.printStackTrace();
		}
		return rslt;
		
	}
