	@Override
	public synchronized String getLabTokenNo(String caseStatus) 
	{
		StringBuffer query=new StringBuffer();
		List<LabelBean> tokenNos=null;
		String token="";
		SimpleDateFormat sdf=new SimpleDateFormat("dd-MM-yyyy");
		String todayDate=sdf.format(new Date());
		try{
		query.append("select count(*) as COUNT from ehf_case ec where ec.case_status='"+caseStatus+"'");
		query.append("  and TRUNC(ec.lst_upd_dt)= TO_DATE('"+todayDate+"','DD-MM-YYYY')");
		tokenNos=genericDao.executeSQLQueryList(LabelBean.class, query.toString());
		
		int tokenNo=0;
		if(tokenNos.get(0)!=null && tokenNos.get(0).getCOUNT()!=null )
		{
			token=String.valueOf(tokenNos.get(0).getCOUNT());
			tokenNo=Integer.parseInt(token);
			if(tokenNo==0)
			{
				tokenNo=1;
			}
			else 
			{
				tokenNo=tokenNo+1;
			}
			token=String.valueOf(tokenNo);
		}
		}
		catch(Exception e)
		{
			e.printStackTrace();
		}
		
		return token;
	}
	
