	public boolean updateDrugsInventory(List<LabelBean> drDetails)
	{
		StringBuffer query=new StringBuffer();
		
		Date todayDate=new Date();
		boolean flag=false;
		
		try{
			if(drDetails!=null && drDetails.get(0)!=null)
			{
				LabelBean drugDtls=drDetails.get(0);
				query.append("select id.dispId as ID from EhfmDispUsrMpg where id.userId='"+drugDtls.getUSERID()+"'");
				List<LabelBean> dispId=genericDao.executeHQLQueryList(LabelBean.class, query.toString());
				if(dispId!=null && dispId.get(0)!=null && dispId.get(0).getID()!=null )
				{
					String dispCode=dispId.get(0).getID();
					
					String drugName=drugDtls.getDrugName();
					if(drugName.equalsIgnoreCase("Others"))
					{
						String sequence=getSequenceVal("DISP_OTHER_DRUG_SEQ");
						String drugId="E"+sequence;
						String drugPrice=drugDtls.getDRUGAMOUNT();
						String drugType=drugDtls.getDrugType();
						String newDrugName=drugDtls.getNewDrugName().toUpperCase();
						
						//Saving New Drug Details to EHFM_DISP_DRUG
						EhfmDispDrug drug=new EhfmDispDrug();
						drug.setDrugId(drugId);
						drug.setDrugTypeId(drugType);
						drug.setDrugName(newDrugName);
						drug.setCrtUsr(drugDtls.getUSERID());
						drug.setCrtDate(todayDate);
						
						
						String mftName=drugDtls.getManufaturerName();
						String mnfctrId="";
						if(mftName.contains("-"))
						{
							String[] arr=mftName.split("-");
							mnfctrId=arr[1];
						}
						else
						{
							//Creating new Manufacuturer
							String mnfSequence=getSequenceVal("DISP_DRUG_MANUFACTURER_SEQ");
							mnfctrId="MNF"+mnfSequence;
							EhfmDispDrugMnfctr mnfctr=new EhfmDispDrugMnfctr();
							mnfctr.setMnfctrId(mnfctrId);
							mnfctr.setMnfctrName(drugDtls.getManufaturerName().toUpperCase());
							mnfctr.setCrtUsr(drugDtls.getUSERID());
							mnfctr.setCrtDate(todayDate);
							genericDao.save(mnfctr);
						}
						
						
						
						
						String dstrName=drugDtls.getDistributerName();
						String dstrbtrId="";
						if(dstrName.contains("-"))
						{
							String[] arr=dstrName.split("-");
							dstrbtrId=arr[1];
						}
						else
						{
							//Creating new Distributer
							String dstrSequence=getSequenceVal("DISP_DRUG_DISTRIBUTER_SEQ");
							dstrbtrId="DST"+dstrSequence;
							EhfmDispDrugDstrbtr dbtr=new EhfmDispDrugDstrbtr();
							dbtr.setDstrbtrId(dstrbtrId);
							dbtr.setDstrbtrName(drugDtls.getDistributerName().toUpperCase());
							dbtr.setCrtUsr(drugDtls.getUSERID());
							dbtr.setCrtDate(todayDate);
							genericDao.save(dbtr);
							
						}
						
						
						
						//Saving Drug Details to Master EHFM_DISP_DRUG_MSTR
						String drugCodeSequence=getSequenceVal("DISP_DRUG_CODE_SEQ");
						String drugCode="DRG"+drugCodeSequence;
						EhfmDispDrugMstr mstr=new EhfmDispDrugMstr();
						mstr.setDrugCode(drugCode);
						mstr.setDrugId(drugId);
						mstr.setDrugTypeId(drugType);
						mstr.setMnfctrId(mnfctrId);
						mstr.setDstrbtrId(dstrbtrId);
						double price=Double.parseDouble(drugPrice);
						mstr.setPrice(price);
						mstr.setBatchNo(drugDtls.getBatchNo().toUpperCase());
						mstr.setQuantity(drugDtls.getQuantity());
						//mstr.setInvoiceNumber(drugDtls.getINVOICENUMBER().toString());
						mstr.setDispId(dispCode);
						mstr.setExpiryDate(drugDtls.getExpiryDate());
						mstr.setActiveYN("Y");
						mstr.setCrtUsr(drugDtls.getUSERID());
						mstr.setCrtDate(todayDate);
						mstr.setLstUpdDate(todayDate);
						mstr.setLstUpdUsr(drugDtls.getUSERID());
						
						
						EhfmDispDrugAudit audit=new EhfmDispDrugAudit();
						long actOrder=1;
						EhfmDispDrugAuditId id=new EhfmDispDrugAuditId(drugCode,actOrder);
						audit.setId(id);
						//audit.setBatchNo(drugDtls.getBatchNo());
						audit.setPharmacistId(drugDtls.getUSERID());
						//audit.setExpiryDate(drugDtls.getExpiryDate());
						audit.setQuantity(drugDtls.getQuantity().toString());
						audit.setInvoiceNumber(drugDtls.getINVOICENUMBER().toString());
						audit.setInvoiceDate(drugDtls.getInvDate());
						audit.setCrtDate(todayDate);
						audit.setDispCode(dispCode);
						//audit.setDrugType(drugDtls.getDrugType());
						genericDao.save(audit);
						
						genericDao.save(drug);
						genericDao.save(mstr);
						flag=true;
						
					}
					else
					{
						for(int i=0;i<drDetails.size();i++)
						{
							LabelBean drgDtls=drDetails.get(i);
							if(drgDtls!=null && drgDtls.getDrugCode()!=null && !"".equalsIgnoreCase(drgDtls.getDrugCode()) )
							{
								EhfmDispDrugMstr mstr=null;
								mstr=genericDao.findById(EhfmDispDrugMstr.class, String.class, drgDtls.getDrugCode());
								if(mstr!=null)
								{
									long availableQuatity=mstr.getQuantity();
									long totQuantity=availableQuatity+drgDtls.getQuantity();
									mstr.setQuantity(totQuantity);
									//String invoiceNumber=drgDtls.getINVOICENUMBER();
									//mstr.setInvoiceNumber(drgDtls.getINVOICENUMBER().toString());
									//mstr.setBatchNo(drgDtls.getBatchNo());
									mstr.setLstUpdUsr(drgDtls.getUSERID());
									mstr.setLstUpdDate(todayDate);
									
									
									StringBuffer query1=new StringBuffer();
									EhfmDispDrugAudit audit=new EhfmDispDrugAudit();
									query1.append("select count(id.actOrder) as COUNT from EhfmDispDrugAudit where id.drugCode='"+drgDtls.getDrugCode()+"'");
									List<LabelBean> count;
									count=genericDao.executeHQLQueryList(LabelBean.class, query1.toString());
									if(count!=null && count.get(0)!=null && count.get(0).getCOUNT()!=null)
									{
										long actOrder=(Long) count.get(0).getCOUNT()+1;
										EhfmDispDrugAuditId id=new EhfmDispDrugAuditId(drgDtls.getDrugCode(),actOrder);
										audit.setId(id);
										//audit.setBatchNo(drgDtls.getBatchNo());
										audit.setPharmacistId(drgDtls.getUSERID());
										audit.setQuantity(drgDtls.getQuantity().toString());
										audit.setInvoiceNumber(drgDtls.getINVOICENUMBER().toString());
										audit.setInvoiceDate(drgDtls.getInvDate());
										
										audit.setCrtDate(todayDate);
										audit.setDispCode(dispCode);
										genericDao.save(audit);
										genericDao.save(mstr);
										flag=true;
										
									}
								}
							}
							
						}
					}
					
					
					
					
				}
				
			}
			
		}
		catch(Exception e)
		{
			e.printStackTrace();
		}
		
		return flag;
	}
	@Override
	public List<DrugsVO> getDispInventDrugBal(LabelBean drugBalParam) {
		List<DrugsVO> drugsBal=new ArrayList<DrugsVO>();
		StringBuffer query=new StringBuffer();
		try{
			if(drugBalParam.getSEARCHTYPE()!=null && !"".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()) && "Avbl".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()))
			{
				query.append("select DDT.drugTypeName as drugTypeName, DD.drugName as drugName, sum(DDM.quantity) as outDrugsQuantity from EhfmDispDrugMstr DDM, EhfmDispDrug DD, EhfmDispDrugType DDT where DDM.drugId = DD.drugId and DDM.drugTypeId = DDT.drugTypeId  and DDM.activeYN='Y' and DDM.id.dispId = '"+drugBalParam.getHOSPID()+"'");
				if(drugBalParam.getDrugType()!=null && !"".equalsIgnoreCase(drugBalParam.getDrugType()) && !"-1".equalsIgnoreCase(drugBalParam.getDrugType()))
				{
					query.append("and DDM.drugTypeId='"+drugBalParam.getDrugType()+"'");
				}
				if(drugBalParam.getDrugId()!=null && !"".equalsIgnoreCase(drugBalParam.getDrugId()) && !"-1".equalsIgnoreCase(drugBalParam.getDrugId()))
				{
					query.append("and DDM.drugId='"+drugBalParam.getDrugId()+"'");
				}
				if(drugBalParam.getSEARCHTYPE()!=null && !"".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()) && "Avbl".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()))
				{
					query.append("and DDM.quantity > 0 and trunc(DDM.expiryDate) >= trunc(sysdate) ");
				}
				if(drugBalParam.getSEARCHTYPE()!=null && !"".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()) && "Avblbatch".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()))
				{
					query.append("and DDM.quantity > 0 and trunc(DDM.expiryDate) >= trunc(sysdate) ");
				}
				query.append(" group by DDT.drugTypeName, DD.drugName ");
				query.append(" order by DDT.drugTypeName, DD.drugName ");
			}
			else if(drugBalParam.getSEARCHTYPE()!=null && !"".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()) && "All".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()))
			{
				//Chandana - 8251 - Added drugcode in the query to get the drugcode
				query.append("select DDT.drugTypeName as drugTypeName, DD.drugName as drugName, sum(DDM.quantity) as outDrugsQuantity, DDM.drugCode AS dispDrugMstrDrgCode from EhfmDispDrugMstr DDM, EhfmDispDrug DD, EhfmDispDrugType DDT where DDM.drugId = DD.drugId and DDM.drugTypeId = DDT.drugTypeId  and DDM.activeYN='Y' and DDM.id.dispId = '"+drugBalParam.getHOSPID()+"'");
				if(drugBalParam.getDrugType()!=null && !"".equalsIgnoreCase(drugBalParam.getDrugType()) && !"-1".equalsIgnoreCase(drugBalParam.getDrugType()))
				{
					query.append("and DDM.drugTypeId='"+drugBalParam.getDrugType()+"'");
				}
				if(drugBalParam.getDrugId()!=null && !"".equalsIgnoreCase(drugBalParam.getDrugId()) && !"-1".equalsIgnoreCase(drugBalParam.getDrugId()))
				{
					query.append("and DDM.drugId='"+drugBalParam.getDrugId()+"'");
				}
				if(drugBalParam.getSEARCHTYPE()!=null && !"".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()) && "Avbl".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()))
				{
					query.append("and DDM.quantity > 0 and trunc(DDM.expiryDate) >= trunc(sysdate)  ");
				}
				if(drugBalParam.getSEARCHTYPE()!=null && !"".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()) && "Avblbatch".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()))
				{
					query.append("and DDM.quantity > 0 and trunc(DDM.expiryDate) >= trunc(sysdate) ");
				}
				query.append(" group by DDT.drugTypeName, DD.drugName, DDM.drugCode ");//Chandana - 8251 - Added DDM.drugCode in group by
				query.append(" order by DDT.drugTypeName, DD.drugName ");
			}
			else{
			query.append("select DDT.drugTypeName as drugTypeName, DD.drugName as drugName, DDM.quantity as outDrugsQuantity, DDMF.mnfctrName as dispDrugMfg,DDDS.dstrbtrName as dispDrugDsbtr, DDM.batchNo as batchNo, TO_CHAR(DDM.expiryDate, 'DD-MM-YYYY') as expiryDt, DDM.drugCode as dispDrugMstrDrgCode  from EhfmDispDrugMstr DDM, EhfmDispDrug DD, EhfmDispDrugType DDT, EhfmDispDrugMnfctr DDMF, EhfmDispDrugDstrbtr DDDS where DDM.drugId = DD.drugId and DDM.drugTypeId = DDT.drugTypeId and DDM.mnfctrId=DDMF.mnfctrId and DDM.dstrbtrId=DDDS.dstrbtrId and DDM.activeYN='Y' and DDM.id.dispId = '"+drugBalParam.getHOSPID()+"'");
			if(drugBalParam.getDrugType()!=null && !"".equalsIgnoreCase(drugBalParam.getDrugType()) && !"-1".equalsIgnoreCase(drugBalParam.getDrugType()))
			{
				query.append("and DDM.drugTypeId='"+drugBalParam.getDrugType()+"'");
			}			
			if(drugBalParam.getDrugId()!=null && !"".equalsIgnoreCase(drugBalParam.getDrugId()) && !"-1".equalsIgnoreCase(drugBalParam.getDrugId()))
			{
				query.append("and DDM.drugId='"+drugBalParam.getDrugId()+"'");
			}
			if(drugBalParam.getSEARCHTYPE()!=null && !"".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()) && "Avbl".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()))
			{
				query.append("and DDM.quantity > 0 and trunc(DDM.expiryDate) >= trunc(sysdate) ");
			}
			if(drugBalParam.getSEARCHTYPE()!=null && !"".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()) && "Avblbatch".equalsIgnoreCase(drugBalParam.getSEARCHTYPE()))
			{
				query.append("and DDM.quantity > 0 and trunc(DDM.expiryDate) >= trunc(sysdate) ");
			}
			query.append("order by DDT.drugTypeName, DD.drugName");
			}
			drugsBal=genericDao.executeHQLQueryList(DrugsVO.class, query.toString());
			
		}
		catch(Exception e)
		{
			e.printStackTrace();
		}
		
		return drugsBal;
	}
	
	public List<LabelBean> getDispDrugDetails(String drugType,String drugId,String userId,String transferType)
	{
		StringBuffer query=new StringBuffer();
		StringBuffer query1=new StringBuffer();
		List<LabelBean> details=null;
		try{
			query.append("select id.dispId as ID from EhfmDispUsrMpg where id.userId='"+userId+"'");
			List<LabelBean> dispId=genericDao.executeHQLQueryList(LabelBean.class, query.toString());
			if(dispId!=null && dispId.get(0)!=null && dispId.get(0).getID()!=null )
			{
				query1.append("select edm.mnfctrName as manufaturerName,ed.dstrbtrName as distributerName,em.drugCode as ID,em.price as drugPrice,em.quantity as quantity, em.expiryDate as expiryDate, em.batchNo as batchNo");
				query1.append(" from EhfmDispDrugMstr em ,EhfmDispDrugMnfctr edm, EhfmDispDrugDstrbtr ed where em.mnfctrId=edm.mnfctrId and em.dstrbtrId=ed.dstrbtrId and ");
				query1.append( " em.drugId='"+drugId+"' and em.dispId='"+dispId.get(0).getID()+"' and em.drugTypeId='"+drugType+"' ");
				if(transferType != null && !"".equals(transferType))
				{
					query1.append( " and em.expiryDate > trunc(sysdate) and em.quantity > 0  ");
				}
					query1.append(" and em.expiryDate > trunc(sysdate) and em.activeYN='Y' ");
				details=genericDao.executeHQLQueryList(LabelBean.class, query1.toString());
				
			}
			
		}
		catch(Exception e)
		{
			e.printStackTrace();
		}
	
		
		return details;
	}
	
