	public boolean addNewMnfNDist(LabelBean drgDetails)
	{
		StringBuffer query=new StringBuffer();
		
		Date todayDate=new Date();
		boolean flag=false;
		int check=0;
		
		try{
			if(drgDetails!=null && drgDetails.getUSERID()!=null )
			{
				query.append("select id.dispId as ID from EhfmDispUsrMpg where id.userId='"+drgDetails.getUSERID()+"'");
				List<LabelBean> dispId=genericDao.executeHQLQueryList(LabelBean.class, query.toString());
				
				if(dispId!=null && dispId.get(0)!=null && dispId.get(0).getID()!=null )
				{
					String dispCode=dispId.get(0).getID();
					
					String drugName=drgDetails.getDrugName();
						String drugId=drgDetails.getDrugId();
						double drugPrice=drgDetails.getDrugPrice();
						String drugType=drgDetails.getDrugType();
						String mftName=drgDetails.getManufaturerName();
						String dstrName=drgDetails.getDistributerName();
						String price=String.valueOf(drugPrice);
						String batchNo=drgDetails.getBatchNo();
						String invoiceNumber=drgDetails.getINVOICENUMBER();
						String contractYear=drgDetails.getCONTRACTYEAR();
						String itemId=drgDetails.getITEMID();
						
						StringBuffer query1=new StringBuffer();
						String mfdId="";
						if(mftName.contains("-"))
						{
							String[] arr=mftName.split("-");
							mfdId=arr[1];
						}
						else
						{
							mfdId=mftName;
						}
						String dstId="";
						if(dstrName.contains("-"))
						{
							String[] arr=dstrName.split("-");
							dstId=arr[1];
						}
						else
						{
							dstId=dstrName;
						}
						if(mftName.contains("-") || dstrName.contains("-"))
						{
							query1.append("select drugCode as ID from EhfmDispDrugMstr where drugId='"+drugId+"' and drugTypeId='"+drugType+"' ");
							query1.append(" and mnfctrId='"+mfdId+"' and dstrbtrId='"+dstId+"' and  price='"+price+"' and UPPER(batchNo) LIKE UPPER('"+batchNo+"')  and dispId='"+dispCode+"'");
							List<LabelBean> dcode=genericDao.executeHQLQueryList(LabelBean.class, query1.toString());
							if(dcode!=null && dcode.size()>0)
							{
								if(dcode.get(0)!=null && dcode.get(0).getID()!=null)
								{
									check=1;
									String drugCode=dcode.get(0).getID();
									EhfmDispDrugMstr mstr=null;
									mstr=genericDao.findById(EhfmDispDrugMstr.class, String.class, drugCode);
									if(mstr!=null)
									{
										long availableQuatity=mstr.getQuantity();
										long totQuantity=availableQuatity+drgDetails.getQuantity();
										mstr.setQuantity(totQuantity);
										mstr.setBatchNo(drgDetails.getBatchNo().toUpperCase());
										mstr.setLstUpdUsr(drgDetails.getUSERID());
										mstr.setLstUpdDate(todayDate);
										
										StringBuffer query2=new StringBuffer();
										EhfmDispDrugAudit audit=new EhfmDispDrugAudit();
										query2.append("select count(id.actOrder) as COUNT from EhfmDispDrugAudit where id.drugCode='"+drugCode+"'");
										List<LabelBean> count;
										count=genericDao.executeHQLQueryList(LabelBean.class, query2.toString());
										if(count!=null && count.get(0)!=null && count.get(0).getCOUNT()!=null)
										{
											long actOrder=(Long) count.get(0).getCOUNT()+1;
											EhfmDispDrugAuditId id=new EhfmDispDrugAuditId(drugCode,actOrder);
											audit.setId(id);
											//audit.setBatchNo(drgDetails.getBatchNo());
											audit.setPharmacistId(drgDetails.getUSERID());
											audit.setQuantity(drgDetails.getQuantity().toString());
											audit.setInvoiceNumber(drgDetails.getINVOICENUMBER());
											audit.setInvoiceDate(drgDetails.getInvDate());
											audit.setCrtDate(todayDate);
											audit.setDispCode(dispCode);
											genericDao.save(audit);
											genericDao.save(mstr);
											flag=true;
											
										}
									}
								}
								
							}
						}
						
						if(check==0)
						{
							String mnfctrId="";
				
							//Saving Drug Details to Master EHFM_DISP_DRUG_MSTR
							String drugCodeSequence=getSequenceVal("DISP_DRUG_CODE_SEQ");
							String drugCode="DRG"+drugCodeSequence;
							EhfmDispDrugMstr mstr=new EhfmDispDrugMstr();
							mstr.setDrugCode(drugCode);
							mstr.setDrugId(drugId);
							mstr.setDrugTypeId(drugType);
							mstr.setMnfctrId(mfdId);
							mstr.setDstrbtrId(dstId);
							mstr.setPrice(drugPrice);
							mstr.setBatchNo(drgDetails.getBatchNo());
							mstr.setQuantity(drgDetails.getQuantity());
							mstr.setDispId(dispCode);
							mstr.setExpiryDate(drgDetails.getExpiryDate());
							mstr.setActiveYN("Y");
							mstr.setCrtUsr(drgDetails.getUSERID());
							mstr.setCrtDate(todayDate);
							mstr.setLstUpdDate(todayDate);
							mstr.setLstUpdUsr(drgDetails.getUSERID());
							mstr.setContractYear(drgDetails.getCONTRACTYEAR());
							mstr.setItemId(drgDetails.getITEMID());
							
							
							EhfmDispDrugAudit audit=new EhfmDispDrugAudit();
							long actOrder=1;
							EhfmDispDrugAuditId id=new EhfmDispDrugAuditId(drugCode,actOrder);
							audit.setId(id);
							//audit.setBatchNo(drgDetails.getBatchNo());
							audit.setPharmacistId(drgDetails.getUSERID());
							//audit.setExpiryDate(drgDetails.getExpiryDate());
							audit.setQuantity(drgDetails.getQuantity().toString());
							audit.setInvoiceNumber(drgDetails.getINVOICENUMBER());
							audit.setInvoiceDate(drgDetails.getInvDate());
							audit.setCrtDate(todayDate);
							audit.setDispCode(dispCode);
							//audit.setDrugType(drgDetails.getDrugType());
							genericDao.save(audit);
							
							genericDao.save(mstr);
							flag=true;
						}
						
					
				}
			}
		}
		catch(Exception e)
		{
			e.printStackTrace();
		}
						
		
		return flag;
	}
