	public List<CommonDtlsVO> getPreviousDrugHist(String cardNo){
		StringBuffer query=new StringBuffer();
		List<CommonDtlsVO> drugHist=null;
		try{
			query.append(" select EDDT.DRUG_TYPE_NAME as DRUGTYPE, ED.DRUG_NAME as DRUGNAME, ER.route_Type_Name as ROUTETYPENAME, ER.route_Name as ROUTENAME, ");
			query.append(" ES.strength_Unit_Name as STRENGTHTYPENAME, ES.strength_Name as STRENGTHNAME, EPD.dosage as DOSAGE, EPD.medication_Period as MEDICATIONPERIOD, ");
			query.append(" EPD.QUANTITY as QUANTITY, EPD.Case_Id as PASTCASEID, EPD.Patient_Id as PASTPATIENTID, EDD.DISP_NAME as DISPNAME, to_char(EPD.Crt_Dt,'DD/MM/YYYY') as ISSUEDATE from ehf_patient_drugs EPD, ");
			query.append(" ehfm_disp_drug_type EDDT, ehfm_disp_drug ED, Ehfm_Op_Strength_Mst ES, Ehfm_Op_Route_Mst ER, Ehf_Patient EP, ehf_case EC, Ehfm_Dispensary_Dtls EDD ");
			query.append(" where EDDT.DRUG_TYPE_ID = EPD.DRUG_TYPE_CODE AND ED.DRUG_ID = EPD.DRUG_SUB_TYPE_CODE AND EPD.patient_Id = EP.patient_Id and EC.CASE_PATIENT_NO=EP.PATIENT_ID ");
			query.append(" and EP.from_disp = 'Y' and EP.drug_disp_flag = 'Y' and EP.card_no = '"+cardNo+"' and trunc(EPD.crt_dt) >= trunc(sysdate - 10) ");
			query.append(" and EDD.DISP_ID=EP.DISP_CODE and ER.route_Code(+) = EPD.route and ES.strength_Code(+) = EPD.strength order by EPD.Crt_Dt");			
			drugHist=genericDao.executeSQLQueryList(CommonDtlsVO.class, query.toString());	
		}
		catch(Exception e)
		{
			e.printStackTrace();
		}
		return drugHist;
	}
