	@Override
	public void generateSendInvReports(String patientId){
		List<LabelVO> invRepDetails=null;
		File lPdffile = null ;
		String lStrFileName="",lStrFileName1="" ,lStrDirPath="",ltImagePath="",rtImagePath="",signImagePath="",signedName="";
		String patientDistrict=null, relationName=null, dispName=null, mailId=null;; 		 
		ltImagePath=config.getString("reportLeftHeaderLogo");
		rtImagePath=config.getString("reportRighttHeaderLogo");
		
		
		 SimpleDateFormat dateFormat = new SimpleDateFormat("MMM");
		 SimpleDateFormat yearFormat = new SimpleDateFormat("YYYY");
		 SimpleDateFormat sdf = new SimpleDateFormat("dd-MM-yyyy");
		 String thisMonth = dateFormat.format(new Date());
		 String thisYear=yearFormat.format(new Date());
		 List<LabelBean>  investList =  getPatInvestList(patientId);
		HashMap lParameterMap=new HashMap();
		lParameterMap.put("patientId",patientId);
		lParameterMap.put("combinedReport","Y");
		invRepDetails=retrieveLabelsData(lParameterMap);
		EhfPatient ehfPatient=genericDao.findById(EhfPatient.class, String.class, patientId);
		if(ehfPatient!=null){
			try {
				patientDistrict= getLocationName(ehfPatient.getDistrictCode());
			} catch (Exception e1) {
				e1.printStackTrace();
			}
			
			EhfmDispensaryDtls asrimHospitals=genericDao.findById(EhfmDispensaryDtls.class,String.class,ehfPatient.getDispCode());
			if(asrimHospitals!=null){
			signImagePath=asrimHospitals.getLabreport_sign_path();
			signedName=asrimHospitals.getLabreportAuthorizedBy();
			dispName=asrimHospitals.getDispName();
			}
			try {
				relationName=getRelationName(ehfPatient.getRelation());
			} catch (Exception e1) {
				// TODO Auto-generated catch block
				e1.printStackTrace();
			}
			lStrDirPath=config.getString("mapPathPatientMailInvReport");
			lStrFileName=patientId+config.getString("DOT_VALUE")+config.getString("ACC.PdfExtn");
			lStrDirPath=lStrDirPath+"/"+thisYear+"/"+thisMonth+"/"+ehfPatient.getDispCode();
			lStrFileName1=lStrDirPath+"/"+lStrFileName;
			lParameterMap.put("patientDistrict",patientDistrict);
			lParameterMap.put("lStrFileName1",lStrFileName1);
			lParameterMap.put("ltImagePath",ltImagePath);
			lParameterMap.put("rtImagePath",rtImagePath);
			lParameterMap.put("signImagePath",signImagePath);
			lParameterMap.put("signedName",signedName);
			lParameterMap.put("dispName",dispName);
			lParameterMap.put("relationName",relationName);
			try {
				lPdffile = PatientInvestReportPdfGenerator.createFile(lStrDirPath,lStrFileName1);
				PatientInvestReportPdfGenerator.genPdfInvestReport(lPdffile, invRepDetails, investList, ehfPatient, lParameterMap);
				if(ehfPatient.getEmailId()!=null && !ehfPatient.getEmailId().equals(""))
				{
					mailId=ehfPatient.getEmailId();
					String[] emailToArray = {mailId};
					EmailVO emailVO = new EmailVO();
					emailVO.setTemplateSource(EmailConstants.TEMPLATE_FROM_FA);
					
					emailVO.setFromEmail(config.getString("emailFrom"));
					emailVO.setToEmail(emailToArray);
					emailVO.setSubject(config.getString("patientEmailSubject"));
					Map<String, String> model = new HashMap<String, String>();
					model.put("patientName", ehfPatient.getName().trim());
					model.put("registeredHosp", dispName);
					model.put("status", "Investigations Report Generated");
					model.put("statusDate",sdf.format(new Date()));
					model.put("lStrFileName1",lStrFileName1);
					model.put("lStrFileName",lStrFileName);
					emailVO.setTemplateName(config.getString("EHFPatientTemplateName"));
					generateMail(emailVO, model);
				}
				
				
			} catch (Exception e) {
				e.printStackTrace();
			}
			
		}
	}
	public String generateMail(EmailVO emailVO, Map mailMap) 
	{
		
		String status="Success";
	    try {

		        String file =(String) mailMap.get("lStrFileName1") ;
		        String fileName = (String) mailMap.get("lStrFileName") ;
		        
	        SimpleMailMessage mailMessage = new SimpleMailMessage();
			mailMessage.setFrom(emailVO.getFromEmail());
			mailMessage.setSubject(emailVO.getSubject());
			mailMessage.setTo(emailVO.getToEmail());
			mailMessage.setSentDate(new java.sql.Timestamp(new Date().getTime()));

			  emailNotifier.sendAttachMessage(mailMessage, emailVO.getTemplateName(),mailMap, emailVO.getTemplateSource(),fileName,file);
//			  System.out.println("MAIL SENT SUCCESSFULLY");
			  
	    } catch (Exception e) {
	    	status="Failed";
	        e.printStackTrace();
	    }
	    return status;
	}
