	@Override
	public String cancelPatient(PatientVO patVo) 
	{
		String msg="";
		try
		{
			if(patVo.getPatientId() != null && !"".equalsIgnoreCase(patVo.getPatientId()))
			{
				EhfPatient ehfPat=genericDao.findById(EhfPatient.class,String.class,patVo.getPatientId());
				if(ehfPat != null)
				{
					ehfPat.setRegisterYN("N");
					if(patVo.getCancelRemarks()!=null && !"".equalsIgnoreCase(patVo.getCancelRemarks()))
					{
						ehfPat.setCancelRemarks(patVo.getCancelRemarks());
					}
					ehfPat.setLstUpdDt(new java.sql.Timestamp(new Date().getTime()));
					ehfPat.setLstUpdUsr(patVo.getLstUpdUsr());
					genericDao.save(ehfPat);
					msg="Patient registration cancelled";
				}
			}
			else
			{
				EhfCase ehfCase=genericDao.findById(EhfCase.class,String.class,patVo.getCaseId());
				if(ehfCase != null)
				{
					ehfCase.setPreauthCancelDt(new java.sql.Timestamp(new Date().getTime()));
					ehfCase.setLstUpdDt(new java.sql.Timestamp(new Date().getTime()));
					ehfCase.setLstUpdUsr(patVo.getLstUpdUsr());
					ehfCase.setCaseStatus("CD601");
					genericDao.save(ehfCase);
					msg="Patient registration cancelled";
				}
			}
		}
		catch(Exception e)
		{
			e.printStackTrace();
//			GLOGGER.error("Exception Occurred in cancelPatient() in PatientDaoImpl class."+e.getMessage());
			msg="Failure";
		}
		return msg;
	}
	@Override
	public String cancelPatientReg(PatientVO patVo) 
	{
		String msg="";
		List<LabelBean> crticalStatus=new ArrayList<LabelBean>();
		try
		{
			if(patVo.getCardNo() != null && !"".equalsIgnoreCase(patVo.getCardNo()))
			{
				StringBuffer query=new StringBuffer();
				query.append( " select entry_id as ENTRY_ID   from mhc_entries WHERE emp_id='"+patVo.getCardNo()+"' and active_yn='Y' ");
				crticalStatus=genericDao.executeSQLQueryList(LabelBean.class, query.toString());
				if(crticalStatus != null)
				{
					List<GenericDAOQueryCriteria> criteriaList = new ArrayList<GenericDAOQueryCriteria>(); 
					criteriaList.add(new GenericDAOQueryCriteria("id.entryId",crticalStatus.get(0).getENTRY_ID(),GenericDAOQueryCriteria.CriteriaOperator.EQUALS));
					List<MhcEntries> mhcEntries = genericDao.findAllByCriteria(MhcEntries.class, criteriaList);
					if(mhcEntries!=null && mhcEntries.size()>0){
				    	if(mhcEntries.get(0)!=null)
				    	{
				    		MhcEntries mhcEntries1 = mhcEntries.get(0);
				    		mhcEntries1.setActiveYn("N");
				    		mhcEntries1.setAisRemarks(patVo.getGicRemarks());
				    		mhcEntries1.setLstUpdUsr(patVo.getLstUpdUsr());
				    		mhcEntries1.setLstDt(new java.sql.Timestamp(new Date().getTime()));
				    		genericDao.save(mhcEntries1);
				    		msg="Patient Registration Cancelled Successfully ";
				    	}
					}
				}
			}
		}
		catch(Exception e)
		{
			e.printStackTrace();
//			GLOGGER.error("Exception Occurred in cancelPatient() in PatientDaoImpl class."+e.getMessage());
			msg="Failure";
		}
		return msg;
	}
