	/*
	 * @Author Sravan reddy
	 * This is method is used to validate exclusively Sandostatin Injection(S30.1.1) within one month condition 
	 * in Day Care procedures which costs Rs.38000
	 */
	@Override
	public boolean validateSandostatinInj(String patientNo,String icdProcCode) 
	{
		boolean validFlg=false;
		StringBuffer query=new StringBuffer();
		try
		{
			query.append( " select distinct c.ICD_PROC_CODE as ID from EHF_PATIENT a, EHF_cASE b, EHF_CASE_THERAPY c, EHF_PATIENT d ");
			query.append( " where a.PATIENT_ID = '"+patientNo+"' and d.PATIENT_ID = b.CASE_PATIENT_NO and b.CASE_ID = c.CASE_ID ");
			query.append( " and d.CARD_NO = a.CARD_NO and c.ACTIVEYN = 'Y' and b.CASE_STATUS not in ("+config.getString("Preauth_Cancelled_Status").replace('~', ',')+") ");
			query.append( " and c.ICD_PROC_CODE = '"+icdProcCode+"' and c.CRT_DT > (sysdate - 30) ");
			List<LabelBean> caseList=genericDao.executeSQLQueryList(LabelBean.class, query.toString());
			if(caseList.size()>0)
			{
				if(caseList != null && caseList.get(0).getID() != null && caseList.get(0).getID().contains("S30.1.1"))
					validFlg=false;
				else
					validFlg=true;
			}
			else
				validFlg=true;
		}
		catch(Exception e)
		{
			e.printStackTrace();
//			GLOGGER.error("Exception Occurred in validateSandostatinInj() in PatientDaoImpl class."+e.getMessage());
		}
		return validFlg;
	}
	
