	public String saveDocDrugs(PatientVO patientVO)  
	{
		String caseId=null;
	  if(patientVO!=null && patientVO.getCaseId()!=null && !"".equalsIgnoreCase(patientVO.getCaseId()))
	  {
		  caseId=patientVO.getCaseId();
		  EhfPatientDocDrugs ehfDrugs=null;
		  try
		  {
			if(patientVO.getDrugs()!=null)
			{
			
			for(DrugsVO drugsVO : patientVO.getDrugs())
			{
				 if (drugsVO.getDrugTypeCode() == null || drugsVO.getDrugSubTypeCode() == null ||
					        drugsVO.getDosage() == null || "-1".equalsIgnoreCase(drugsVO.getDosage()) ||
					        drugsVO.getMedicationPeriod() == null || drugsVO.getQuantity() == null) {
					        System.out.println("Skipping invalid drug: " + drugsVO);
					        continue;
					    }
				 //end 
				ehfDrugs = new EhfPatientDocDrugs();
				ehfDrugs.setDrugId(drugsVO.getDrugId());
				ehfDrugs.setCaseId(patientVO.getCaseId());
				ehfDrugs.setPatientId(patientVO.getPatientId());
				
					ehfDrugs.setDrugTypeCode(drugsVO.getDrugTypeCode());
					ehfDrugs.setDrugSubTypeCode(drugsVO.getDrugSubTypeCode());
					
			//pravalika
					ehfDrugs.setDosage(drugsVO.getDosage());
				    ehfDrugs.setMedicationPeriod(drugsVO.getMedicationPeriod());
				    ehfDrugs.setQuantity(drugsVO.getQuantity());
				
				/*if(!"-1".equalsIgnoreCase(drugsVO.getDosage()))
					ehfDrugs.setDosage(drugsVO.getDosage());
				ehfDrugs.setMedicationPeriod(drugsVO.getMedicationPeriod());*/
				    

				
				Date date=new Date();
				ehfDrugs.setCrtDt(date);
				ehfDrugs.setCrtUsr(patientVO.getCrtUsr());
				genericDao.save(ehfDrugs);

			}
			}
			EhfPatient ehfPatient=getPatientDetails(patientVO.getPatientId());
			ehfPatient.setPharmaView("Y");
			genericDao.save(ehfPatient);
			
			
		  }
		  catch(Exception e)
		  {
			  e.printStackTrace();
		  }
	  }
	 return caseId;
	}
	

	
