		@Override
		public CreateEmployeeVO getLeaveReport(CreateEmployeeVO createEmpVo) {

			SessionFactory factory=null;
			Session session=null;
			List<CreateEmployeeVO> empList= new ArrayList<CreateEmployeeVO>();
				    
			factory= hibernateTemplate.getSessionFactory();
			session=factory.openSession();
			StringBuffer searchQuery = new StringBuffer();
			StringBuffer countQuery = new StringBuffer();
			try
			{   
			
			    countQuery.append("select count(distinct u.userId) as totValue from EjhsWellnessLeaveDetails u ,EhfmGrps w ,EhfmDispUsrMpg m where w.grpId=u.grpId and  m.id.dispId=u.dispId and m.id.userId='"+createEmpVo.getUserId()+"' ");
			
			
			if(createEmpVo.getFromDate()!=null&& createEmpVo.getFromDate() !="" && !createEmpVo.getFromDate().equals("")){
				countQuery.append(" and u.leaveFomDate = '"+createEmpVo.getFromDate()+"' "); 
			}
			
			if(createEmpVo.getToDate()!=null&& createEmpVo.getToDate()!="" && !createEmpVo.getToDate().equalsIgnoreCase("null")){
				countQuery.append(" and u.leaveToDate='"+createEmpVo.getToDate()+"' ");
			}
			if(createEmpVo.getDesgName()!=null && createEmpVo.getDesgName()!="" && !createEmpVo.getDesgName().equalsIgnoreCase("null")){
				countQuery.append(" and d.id.dsgnId='"+createEmpVo.getDesgId()+"' ");
			}
             empList =session.createQuery(countQuery.toString()).setFirstResult(createEmpVo.getStart_index()).setMaxResults(createEmpVo.getEnd_index()).setResultTransformer(Transformers.aliasToBean(CreateEmployeeVO.class)).list();
			createEmpVo.setEmpSearchList(empList);

			searchQuery.append("select distinct(u.userId) as loginName,u.consultName as fName,u.consultMobile||'' as mobileNo, w.grpName as desgName,u.leaveFomDate||'' as fromDate,u.leaveToDate||'' as toDate,u.crtDt||'' as crtDt from  EjhsWellnessLeaveDetails u ,EhfmGrps w ,EhfmDispUsrMpg m where w.grpId=u.grpId and  m.id.dispId=u.dispId and m.id.userId='"+createEmpVo.getUserId()+"' ");

			if(createEmpVo.getFromDate()!=null&& createEmpVo.getFromDate() !="" && !createEmpVo.getFromDate().equals("")){
				searchQuery.append(" and u.leaveFomDate = '"+createEmpVo.getFromDate()+"' "); 
			}
			
			if(createEmpVo.getToDate()!=null&& createEmpVo.getToDate()!="" && !createEmpVo.getToDate().equalsIgnoreCase("null")){
				searchQuery.append(" and u.leaveToDate='"+createEmpVo.getToDate()+"' ");
			}
			if(createEmpVo.getDesgName()!=null && createEmpVo.getDesgName()!="" && !createEmpVo.getDesgName().equalsIgnoreCase("null")){
				searchQuery.append(" and d.id.dsgnId='"+createEmpVo.getDesgId()+"' ");
			}
			
			Long count = (Long) session.createQuery(countQuery.toString()).setProperties(createEmpVo).uniqueResult();

		   empList =session.createQuery(searchQuery.toString()).setFirstResult(createEmpVo.getStart_index()).setMaxResults(createEmpVo.getEnd_index()).setResultTransformer(Transformers.aliasToBean(CreateEmployeeVO.class)).list();
			
			
			createEmpVo.setEmpSearchList(empList);
			createEmpVo.setTotRowCount(count.intValue());
			
		} catch (Exception e) {
			
			e.printStackTrace();
		}
		finally
		{
		   session.close();
		   factory.close();
		   
		}
			return createEmpVo;
			
			
		}

