		@Override
		public String regPatient(PatientVO patVo) {
			String packg="";
			try{
			String ayushVal="";
			StringBuffer query=new StringBuffer();
			query.append(" SELECT ayush_services as ID FROM ehf_patient where patient_id= '"+patVo.getPatientId()+"' ");
			List<LabelBean> newBeanLst=genericDao.executeSQLQueryList(LabelBean.class, query.toString());
			if(newBeanLst != null && newBeanLst.size() >0 && newBeanLst.get(0)!=null)
			{
				ayushVal=newBeanLst.get(0).getID();
			}
			String temp="";
			
			if(ayushVal!=null && !"".equalsIgnoreCase(ayushVal))
			{
				String[] arr=ayushVal.split("~");
				if(arr!=null && arr.length>0)
				{
					for(int i=0;i<arr.length;i++)
					{
						temp=temp+"'"+arr[i]+"',";
					}
					temp=temp.substring(0,temp.length()-1);
				}
			}
			
			StringBuffer qr=new StringBuffer();
			qr.append("select package_code as ID, package_name as VALUE from ais_packages where package_code in ("+temp+")");
			List<LabelBean> packages=genericDao.executeSQLQueryList(LabelBean.class, qr.toString());
			
			
			if(packages!=null && packages.size()>0)
			{
				for(LabelBean lb:packages)
				{
					if(lb!=null && lb.getVALUE()!=null && !"".equalsIgnoreCase(lb.getVALUE()))
					{
						List<GenericDAOQueryCriteria> criteriaList = new ArrayList<GenericDAOQueryCriteria>(); 
						criteriaList.add(new GenericDAOQueryCriteria("testId",lb.getID(),GenericDAOQueryCriteria.CriteriaOperator.EQUALS));
						criteriaList.add(new GenericDAOQueryCriteria("patientId",patVo.getPatientId(),GenericDAOQueryCriteria.CriteriaOperator.EQUALS));
					    List<AisPatientTests> ehfCaseLst = genericDao.findAllByCriteria(AisPatientTests.class, criteriaList);
					    if(ehfCaseLst!=null && ehfCaseLst.size()>0 && ehfCaseLst.get(0)!=null && ehfCaseLst.get(0).getAttachTotalPath()!=null && !"".equalsIgnoreCase(ehfCaseLst.get(0).getAttachTotalPath())){
					    	
					    	packg=packg+lb.getVALUE()+"^"+lb.getID()+"^"+ehfCaseLst.get(0).getAttachTotalPath()+"~";
					    }
					    else
					    {
						packg=packg+lb.getVALUE()+"^"+lb.getID()+"^EMP~";
					    }
					}
				}
				packg=packg.substring(0,packg.length());
			}
		
			/*if(filePaths!=null && filePaths.size()>0)
			{
				for(LabelBean lb:filePaths)
				{
					if(lb!=null && lb.getVALUE()!=null && !"".equalsIgnoreCase(lb.getVALUE()))
					{
						packg=packg+lb.getVALUE()+"-"+lb.getID()+"~";
					}
				}
				packg=packg.substring(0,packg.length()-1);
			}
			*/
			
			System.out.println(packg);
			}
			catch(Exception e)
			{
				e.printStackTrace();
			}
			
			
			
			return packg;
		}
