		@Override
		public PatientVO getRegistredLhsMembersList(HashMap<String, String> searchMap) {
			SessionFactory factory=null;
			Session session=null;
			String database=config.getString("Database");
			PatientVO patVO = new PatientVO();
			ArrayList<PatientVO> registeredLhsMembersList =new ArrayList<PatientVO>();
			//String schemeId=searchMap.get("schemeId").toString();
		
			try
			{
			StringBuffer sql_query = new StringBuffer();
			
			factory= hibernateTemplate.getSessionFactory();
			session=factory.openSession();
			//sowmya
			String flagVal ="";
			String patientNumber="";
			String editLhsMember = "";
			String srchStatus = null;
			String lhsApproveFlag = null;  //second level approval
			String regFlag = null;   //all register members view
			if("True".equalsIgnoreCase((String)searchMap.get("editLhsMember"))){
				editLhsMember = searchMap.get("editLhsMember").toString();
				patientNumber=searchMap.get("patientNumber").toString();
			}
			
			if ("search".equalsIgnoreCase((String) searchMap.get("searchFlag"))){
			 flagVal = searchMap.get("searchFlag").toString();
			}
			if (searchMap.get("patientNumber") != null && !searchMap.get("patientNumber").trim().isEmpty()) {
				patientNumber = searchMap.get("patientNumber").trim();
			}
			if (searchMap.get("status") != null && !searchMap.get("status").trim().isEmpty()) {
			    srchStatus = searchMap.get("status").trim();
			}
			if (searchMap.get("lhsApproveFlag") != null && !searchMap.get("lhsApproveFlag").trim().isEmpty()) {
				lhsApproveFlag = searchMap.get("lhsApproveFlag").trim();
			}
			if (searchMap.get("registrtionFlag") != null && !searchMap.get("registrtionFlag").trim().isEmpty()) {
				regFlag = searchMap.get("registrtionFlag").trim();
			}

				if("search".equalsIgnoreCase(flagVal)){
					sql_query.append("SELECT ID_NO patientId,USER_NAME NAME,GENDER DSGNID,PHONE_NO VALUE,MEMBER_TYPE TYPE2,CRT_DT CRT_DT,STATUS CASESTATUS FROM LHS_USER_DTLS where ");
					if(patientNumber != null && !patientNumber.trim().isEmpty()) {
					     sql_query.append("ID_NO ='"+patientNumber+"' ");
					}
					if((patientNumber != null && !patientNumber.trim().isEmpty()) && srchStatus != null && !srchStatus.trim().isEmpty()){
						 sql_query.append(" AND ");
					}
					if(srchStatus != null && !srchStatus.trim().isEmpty()) {
					     sql_query.append("STATUS ='"+srchStatus+"' ");
					}
				}else if("True".equalsIgnoreCase(editLhsMember)){
					sql_query.append("SELECT ID_NO patientId,CARD_NO LVL,USER_NAME NAME,GENDER DSGNID,DOB,EMAIL_ID EMAILID,PHONE_NO VALUE,AADHAR_ID AADHARID,FATHER_NAME SUBNAME, ");
					sql_query.append("SPOUSE_NAME DISPNAME,MEMBER_TYPE TYPE2,CONSTITUENCY_NAME ID,DIST_ID DISTRICT,PIN_CODE COUNT,TERM_START_DT REGNDATE, ");
					sql_query.append("TERM_END_DT DT,PERM_ADDRESS ADDRESS,CONST_ADDRESS TYPE1,OFFC_ADDRESS TYPE3,CRT_DT CRT_DT, ");
					sql_query.append("AADHAR_DOC_NAME C1,PHOTO_DOC_NAME C2,SUPPORT_DOC_NAME C3,SUPPORT_ACTUAL_NAME C4,PHOTO_ACTUAL_NAME C5, ");
					sql_query.append("AADHAR_ACTUAL_NAME C6,SIGNED_DOCUMENT_ACTUAL_NAME C7,SIGNED_DOCUMENT_NAME C8,REJ_REMARKS REMARKS,REV_REMARKS TYPE FROM LHS_USER_DTLS ");
					sql_query.append("where ID_NO='"+patientNumber+"' and STATUS='"+srchStatus+"' ");
					
				}
				else{
					sql_query.append("SELECT ID_NO patientId,USER_NAME NAME,GENDER DSGNID,PHONE_NO VALUE,MEMBER_TYPE TYPE2,CRT_DT CRT_DT,STATUS CASESTATUS FROM LHS_USER_DTLS ");
					if("Y".equalsIgnoreCase(lhsApproveFlag)){
					  sql_query.append("where STATUS='RA' OR STATUS = 'R' OR STATUS = 'A' ");
					}else if(!"Y".equalsIgnoreCase(regFlag)){
					  sql_query.append("where STATUS='WA' OR STATUS = 'RA' OR STATUS = 'REV' OR STATUS = 'R' ");
					}
				}
		
			List<LabelBean> dataList = genericDao.executeSQLQueryList(LabelBean.class,sql_query.toString());
			if(dataList.size()>0){
	  	    	for(LabelBean labelData:dataList){
	  	    PatientVO patientVo = new PatientVO();
			patientVo.setFirstName(labelData.getNAME());
			patientVo.setPatientId(labelData.getPATIENTID());
			patientVo.setCardNo(labelData.getLVL());
			
			if(labelData.getDSGNID() !=null && "M".equalsIgnoreCase(labelData.getDSGNID()))
			{
				patientVo.setGender("Male");
			}
			else if(labelData.getDSGNID()!=null && "F".equalsIgnoreCase(labelData.getDSGNID()))
			{
				patientVo.setGender("Female");
			}
			patientVo.setMobile(labelData.getVALUE());
			patientVo.setType1(labelData.getTYPE2());  //member type
			String status = labelData.getCASESTATUS();
			if("A".equalsIgnoreCase(status)){
				patientVo.setCaseStatus("Approved");
			}else if("R".equalsIgnoreCase(status)){
				patientVo.setCaseStatus("Rejected");
			}else if("WA".equalsIgnoreCase(status)){
				patientVo.setCaseStatus("Waiting For Approval");
			}else if("RA".equalsIgnoreCase(status)){
				patientVo.setCaseStatus("Recommended For Approval");
			}else if("REV".equalsIgnoreCase(status)){
				patientVo.setCaseStatus("Returned");
			}
			
			Date doa = labelData.getDOB();
			if(doa != null){
				SimpleDateFormat sdf = new SimpleDateFormat("dd/MM/yyyy");
				String formattedDoa= sdf.format(doa);
				// Set the formatted string to RegHospDt
				patientVo.setDateOfBirth(formattedDoa);
			}
			
			Date crtdt = labelData.getCRT_DT();
			SimpleDateFormat sdf1 = new SimpleDateFormat("dd/MM/yyyy");
			String formattedCrtDt = sdf1.format(crtdt);

			// Set the formatted string to RegHospDt
			patientVo.setRegHospDt(formattedCrtDt);
			Number pincode = labelData.getCOUNT();
			patientVo.setPinCode(pincode != null && pincode.intValue() != 0 ? pincode.intValue() : null);
			patientVo.seteMailId(labelData.getEMAILID());
			patientVo.setAadharID(labelData.getAADHARID());
			patientVo.setFatherName(labelData.getSUBNAME());
			patientVo.setSpouseName(labelData.getDISPNAME());
			patientVo.setMemberType(labelData.getTYPE2());
			patientVo.setConstituency(labelData.getID());
			patientVo.setDistrictCode(labelData.getDISTRICT());
			if(labelData.getCOUNT() != null){
			  patientVo.setPincode(labelData.getCOUNT().toString());
			}
			Date startDate = labelData.getREGNDATE();  //term start date
			if(startDate != null){
				SimpleDateFormat sdf2 = new SimpleDateFormat("dd/MM/yyyy");
				String formattedStartDate = sdf2.format(startDate);
				patientVo.setTermStartDate(formattedStartDate);
			}
			
			Date endDate = labelData.getDT();  //term start date
			if(endDate != null){
				SimpleDateFormat sdf3 = new SimpleDateFormat("dd/MM/yyyy");
				String formattedEndDate = sdf3.format(endDate);
				patientVo.setTermEndDate(formattedEndDate);
			}
			
			patientVo.setPermanentAddress(labelData.getADDRESS());
			patientVo.setConstituencyAddress(labelData.getTYPE1());
			patientVo.setOfficialAddress(labelData.getTYPE3());
			patientVo.setAadharFileName(labelData.getC1());
			patientVo.setPhotoFileName(labelData.getC2());
			patientVo.setSupportFileName(labelData.getC3());
			patientVo.setSupportFilePath(labelData.getC4());
			patientVo.setPhotoFilePath(labelData.getC5());
			patientVo.setAadharFilePath(labelData.getC6());
			
			//signed documnet
			patientVo.setSignedFilePath(labelData.getC7());
			patientVo.setSignedFileName(labelData.getC8());
			patientVo.setResult(labelData.getREMARKS());
			patientVo.setRevertRemarks(labelData.getTYPE());
			
			registeredLhsMembersList.add(patientVo);
	  	    }
			}
			patVO.setRegisteredPatList(registeredLhsMembersList);
			}
			catch(Exception e)
			{
				GLOGGER.error("Exception Occurred in getRegisteredPatients() in PatientDaoImpl class."+e.getMessage());
			e.printStackTrace();
			}
			finally
			{
				session.close();
				factory.close();
			}
			return patVO;
		}
		
