		@Override
		public String updateLhsMemberApproveOrReject(HashMap<String, String> searchMap){
			SessionFactory factory= hibernateTemplate.getSessionFactory();
			Session session=factory.openSession();
			
			LHSPatientDetails patDetails = null;
			String lhsId=searchMap.get("patientNumber").toString();
			
	
			String rejectedReason = null;
			if (searchMap.get("rejectReason") != null && !searchMap.get("rejectReason").toString().trim().isEmpty()) {
			    rejectedReason = searchMap.get("rejectReason").toString().trim();
			}

			String userId=searchMap.get("rejOrAprvUsr").toString();
			
			String lhsMemberApprove = null;
			if (searchMap.get("lhsApprove") != null && !searchMap.get("lhsApprove").toString().trim().isEmpty()) {
				lhsMemberApprove = searchMap.get("lhsApprove").toString().trim();
			}

			
			
			String rejStatus ="R";
			String aprvStatus ="RA";
			String result=null;
			String updQuery = null;
			String dependentQuery = null;
	
			try {
			  patDetails = genericDao.findById(LHSPatientDetails.class,String.class,lhsId);
			  if(patDetails != null){
				  if("true".equalsIgnoreCase(lhsMemberApprove)){
					   updQuery = "UPDATE LHSPatientDetails SET LST_UPD_DT= SYSDATE,"
						  		+ "STATUS='"+aprvStatus+"',LST_UPD_USR='"+userId+"' WHERE ID_NO = '"+lhsId+"' "; 
				  }else{
					  updQuery = "UPDATE LHSPatientDetails SET APPRV_REJ_DT= SYSDATE,"
						  		+ "STATUS='"+rejStatus+"',APPRV_REJ_USR='"+userId+"',REJ_REMARKS='"+rejectedReason+"',ACTIVE_YN='N' WHERE ID_NO = '"+lhsId+"' "; 
				  }
				  
				  Query query = session.createQuery(updQuery);
				  query.executeUpdate();
				  result = "success";
				  if(result == "success"){
					  if("true".equalsIgnoreCase(lhsMemberApprove)){
						  dependentQuery = "UPDATE LhsDependentDtls SET LST_UPD_DT= SYSDATE,"
							  		+ "STATUS='"+aprvStatus+"',LST_UPD_USR='"+userId+"' WHERE ID_NO = '"+lhsId+"' "; 
					  }else{
						  dependentQuery = "UPDATE LhsDependentDtls SET APPRV_REJ_DT= SYSDATE,"
							  		+ "STATUS='"+rejStatus+"',APPRV_REJ_USR='"+userId+"',ACTIVE_YN='N' WHERE ID_NO = '"+lhsId+"' "; 
					  }
					  
					  Query query2 = session.createQuery(dependentQuery);
					  query2.executeUpdate();
				  }
				  
			  }
			} catch (Exception e) {
				e.printStackTrace();
				result = "failure";
			}finally{
				session.close();
				factory.close();
			}
			return result;
		}
		
