				 query.append("  select distinct to_char(ddt.drug_type_name) as DRUGTYPE,       to_char(dm.drug_name) as DRUGNAME ,       p.drug_type_code as DRUGTYPES,       p.drug_sub_type_code as DRUGIDS ,       to_char(sum(dg.doc_quantity)) as PRESC_QUANTITY,       to_char(sum(p.quantity)) as QUANTITY                                ");
