		@Override
		public List<LabelBean> getDrugTypeListAis() {

			List<LabelBean> dispDrugTypeList=new ArrayList<LabelBean>();
			StringBuffer query=new StringBuffer();
			try{
				query.append("select distinct drugTypeId as ID, drugTypeName as VALUE from EhfmDispDrugType where drugTypeId not in ('DT13')  order by drugTypeName");
				dispDrugTypeList=genericDao.executeHQLQueryList(LabelBean.class, query.toString());
				
			}
			catch(Exception e)
			{
				e.printStackTrace();
			}
			
			return dispDrugTypeList;
		
		}
		// done by 1343151
		@Override
	public boolean updateTransferDrugs(HashMap drugparam) throws Exception {
			StringBuffer query=new StringBuffer();
			EhfmDispSubStore  ehfmDispSubStore = null;
			Date todayDate=new Date();
			boolean flag=false;
			String type = null;
			String fromCode = null;
			String toCode = null;
			List<LabelBean>drugList = new ArrayList<>();
			HashMap dtlParam = new HashMap<>();
			String subDrugCode="";
			String toDispId= null;
			 String reqId = null;
			 Long remQuant =0l;
			if(drugparam.get("tdType") != null){
				type=(String)drugparam.get("tdType");
			}
			if(drugparam.get("drugList") != null && ((List<LabelBean>)drugparam.get("drugList")).size() >0){
				drugList =(List<LabelBean>)drugparam.get("drugList");
			}
			if(drugparam.get("toDispId") != null){
				toDispId=(String)drugparam.get("toDispId");
			}
	
			
			
			
		try{
			if(type!=null && !"-1".equals(type) &&  !"".equals(type))
				{
				   LabelBean drugDtls=drugList.get(0);
					query.append("select id.dispId as ID from EhfmDispUsrMpg where id.userId='"+drugDtls.getUSERID()+"'");
					List<LabelBean> dispId=genericDao.executeHQLQueryList(LabelBean.class, query.toString());
			 if(dispId!=null && dispId.get(0)!=null && dispId.get(0).getID()!=null )
			 {
						String dispCode=dispId.get(0).getID();
						String drugType=drugDtls.getDrugType();
						if("WCtoWC".equalsIgnoreCase(type)){
				    	  String sequence1=getSequenceVal("DISP_DRUGTRANS_SEQ");
						    reqId="DTR"+sequence1;
						}
			 for(LabelBean dtls :drugList){
				  ehfmDispSubStore = new EhfmDispSubStore();	
						EhfmDispDrugMstr mstr=null;
						mstr=genericDao.findById(EhfmDispDrugMstr.class, String.class, dtls.getDrugCode());
				if(mstr!=null)
				 { 
					Long avblQuant =mstr.getQuantity();
					if("WCtoD".equalsIgnoreCase(type) || "DtoWC".equalsIgnoreCase(type))
					{     StringBuffer lsb=new StringBuffer();
							lsb.append(" select sub.sub_drugCode  as ID ,sub.quantity as quantity from EhfmDispSubStore sub where ");
							lsb.append(" sub.drugCode='"+dtls.getDrugCode()+"'");
							lsb.append(" and dispId='"+dispCode+"' ");
							List<LabelBean> subList=genericDao.executeHQLQueryList(LabelBean.class, lsb.toString());
						if(subList!=null && subList.size()>0 && subList.get(0)!=null && subList.get(0).getID()!=null )
						{
							subDrugCode =subList.get(0).getID();
								ehfmDispSubStore=genericDao.findById(EhfmDispSubStore.class, String.class, subList.get(0).getID());	
							if(ehfmDispSubStore != null){
									Long quants =ehfmDispSubStore.getQuantity();
							  // Update Quantity in EHFM_DISP_SUB_STORE
								if("WCtoD".equalsIgnoreCase(type)){
									ehfmDispSubStore.setQuantity(quants+dtls.getQuantity());
								 }else if ("DtoWC".equalsIgnoreCase(type)){
									 
									 ehfmDispSubStore.setQuantity(quants-dtls.getQuantity());
								 }
									ehfmDispSubStore.setLstUpdUsr(dtls.getUSERID());
									ehfmDispSubStore.setLstUpdDate(todayDate);
							}
						}else{
						    String sequence=getSequenceVal("DISP_SUB_DRUGSEQ");
						    subDrugCode="SDC"+sequence;
					// Insert drugs into EHFM_DISP_SUB_STORE
							ehfmDispSubStore.setSub_drugCode(subDrugCode);
							ehfmDispSubStore.setDrugCode(dtls.getDrugCode());
							ehfmDispSubStore.setQuantity(dtls.getQuantity());
							ehfmDispSubStore.setMnfctrId(mstr.getMnfctrId());
     						ehfmDispSubStore.setDstrbtrId(mstr.getDstrbtrId());
							ehfmDispSubStore.setExpiryDate(mstr.getExpiryDate());
							ehfmDispSubStore.setPrice(mstr.getPrice());
							ehfmDispSubStore.setDrugId(mstr.getDrugId());
							ehfmDispSubStore.setBatchNo(mstr.getBatchNo());
							ehfmDispSubStore.setDrugTypeId(drugType);
							ehfmDispSubStore.setCrtUsr(dtls.getUSERID());
							ehfmDispSubStore.setCrtDate(todayDate);
							ehfmDispSubStore.setDispId(dispCode);
							ehfmDispSubStore.setActiveYN("Y");
							
						}
						genericDao.save(ehfmDispSubStore);
						
						if("WCtoD".equalsIgnoreCase(type)){
						    remQuant =avblQuant -dtls.getQuantity();
						    fromCode=dtls.getDrugCode();
							 toCode=subDrugCode;
						}else if("DtoWC".equalsIgnoreCase(type)){
							remQuant=avblQuant +dtls.getQuantity();
							fromCode=subDrugCode;
							 toCode=dtls.getDrugCode();
						}
							
							 // Insert into EHFM_DISP_TRANSFER_AUDIT
									dtlParam.put("fromCode", fromCode);
									dtlParam.put("toCode", toCode);
									dtlParam.put("quantity", dtls.getQuantity());
									dtlParam.put("crtUser", dtls.getUSERID());
									flag = insertDrugTransferAudit(dtlParam);
									
									
							
				  }	
			      else if("WCtoWC".equalsIgnoreCase(type)){
			    	  EhfDispDrugTransfer  ehfDispDrugTransfer = new EhfDispDrugTransfer();
			    	  EhfDispDrugTransferPK ehfDispDrugTransferPK= new EhfDispDrugTransferPK();
				// Insert drugs into EHF_DISP_DRUG_TRANSFER 
					    ehfDispDrugTransferPK.setReqstId(reqId);
					    ehfDispDrugTransferPK.setDrugCode(dtls.getDrugCode());
					    ehfDispDrugTransfer.setId(ehfDispDrugTransferPK);
					    ehfDispDrugTransfer.setQuantity(dtls.getQuantity());
					    ehfDispDrugTransfer.setMnfctrId(mstr.getMnfctrId());
					    ehfDispDrugTransfer.setDstrbtrId(mstr.getDstrbtrId());
					    ehfDispDrugTransfer.setExpiryDate(mstr.getExpiryDate());
					    ehfDispDrugTransfer.setPrice(mstr.getPrice());
					    ehfDispDrugTransfer.setDrugId(mstr.getDrugId());
					    ehfDispDrugTransfer.setBatchNo(mstr.getBatchNo());
					    ehfDispDrugTransfer.setDrugTypeId(drugType);
					    ehfDispDrugTransfer.setCrtUsr(dtls.getUSERID());
					    ehfDispDrugTransfer.setCrtDate(todayDate);
					    ehfDispDrugTransfer.setFromDispId(dispCode);
					    ehfDispDrugTransfer.setToDispId(toDispId);
					    ehfDispDrugTransfer.setStatus("init");
					    
					    genericDao.save(ehfDispDrugTransfer);
					    remQuant =avblQuant -dtls.getQuantity();
					    
				  }
					 // Update Quantity in EHFM_DISP_DRUG_MSTR
					mstr.setQuantity(remQuant);
					mstr.setLstUpdUsr(dtls.getUSERID());
					mstr.setLstUpdDate(todayDate);
					
					genericDao.save(mstr);
					flag=true;
					subDrugCode= null;
				  
				}
			  }
			 }
			}
		   }
		   catch(Exception e)
		   {    flag=false;
				e.printStackTrace();
		   }
		
			return flag;
		}
		private boolean insertDrugTransferAudit(HashMap drugParam){
			boolean flag=false;
			String fromCode = null;
			String toCode = null;
			String crtUsr = null;
			long quant = 0l;
			Long actOrder = 1l;
			try{
			Date todayDate=new Date();
			
			if(drugParam.get("fromCode")!= null && !"".equals((String)drugParam.get("fromCode"))){
				fromCode =(String)drugParam.get("fromCode");
			}
            if(drugParam.get("toCode")!= null && !"".equals((String)drugParam.get("toCode"))){
            	toCode =(String)drugParam.get("toCode");
			}
            if(drugParam.get("quantity")!= null){
            	quant =(Long)drugParam.get("quantity");
			}
            if(drugParam.get("crtUser")!= null && !"".equals((String)drugParam.get("crtUser"))){
            	crtUsr=(String)drugParam.get("crtUser");
			}
			StringBuffer query=new StringBuffer();
			query.append("select max(ehfm.id.actOrder) as IDVAL from EhfDispTransferAudit ehfm where ehfm.id.fromCode='"+fromCode+"' and ehfm.id.toCode='"+toCode+"' ");
			List<LabelBean> actOrders=genericDao.executeHQLQueryList(LabelBean.class, query.toString());
			if(actOrders.size()>0 && actOrders.get(0).getIDVAL() != null){
				actOrder =actOrders.get(0).getIDVAL()+1;
			}
			EhfDispTransferAudit ehfDispTransferAudit = new EhfDispTransferAudit();
			EhfDispTransferAuditId ehfDispTransferAuditId = new EhfDispTransferAuditId();
			ehfDispTransferAuditId.setActOrder(actOrder);
			ehfDispTransferAuditId.setFromCode(fromCode);
			ehfDispTransferAuditId.setToCode(toCode);
			
			ehfDispTransferAudit.setId(ehfDispTransferAuditId);
			ehfDispTransferAudit.setQuantity(quant);
			ehfDispTransferAudit.setCrtUsr(crtUsr);
			ehfDispTransferAudit.setCrtDate(todayDate);
			genericDao.save(ehfDispTransferAudit);
			flag = true;
			}catch(Exception e){
				e.printStackTrace();
			}
			
			return flag;
		}
