		@Override
		public List<LabelBean> getexpiredDrugs(Map dataMap) {
			List<LabelBean> expiredDrgList = new ArrayList<>();
			StringBuffer query = new StringBuffer();
			String fromDate = (String)dataMap.get("fromDate");
			String toDate = (String)dataMap.get("toDate");
			String dispName = (String)dataMap.get("dispName");
			String distrbutr =(String)dataMap.get("distrbutr");
			String searchType =(String)dataMap.get("searchType");
			
			try{
				query.append(" SELECT TO_CHAR(SUBSTR(edt.disp_name, 6)) DISP_NAME,                                            ");
				query.append("   TO_CHAR(ddt.drug_type_name)            AS DRUG_TYPE,                                         ");
				query.append("   TO_CHAR(dm.drug_name)                  AS DRUG_NAME,                                         ");
				query.append("   TO_CHAR(ddm.mnfctr_name)               AS MNFCTRNAME,                                        ");
				query.append("   TO_CHAR(ddd.dstrbtr_name)              AS DSTRBTRNAME,                                       ");
				query.append("   TO_CHAR(dmr.batch_no)                  AS BATCHNO,                                           ");
				query.append("   TO_CHAR(dmr.drug_code)                 AS DRUGCODE,                                          ");
				query.append("   TO_CHAR(dmr.expiry_date, 'dd/MM/yyyy') AS EXPDT,                                             ");
				query.append("   TO_CHAR(listagg(to_char(dda.invoice_dt,'DD/MM/RRRR'),', ')                                   ");
				query.append("   within group (order by rownum))   AS ISSUEDATE,                                              ");
				query.append("   TO_CHAR(listagg(dda.invoice_num,', ') within group (order by rownum))   AS INVOICENUMBER,    ");
				query.append("   TO_CHAR(dmr.quantity)                  AS QUANTITY                                           ");
				query.append(" FROM ehfm_dispensary_dtls edt,                                                                 ");
				query.append("   ehfm_disp_drug_type ddt,                                                                     ");
				query.append("   ehfm_disp_drug dm,                                                                           ");
				query.append("   EHFM_DISP_DRUG_AUDIT DDA ,                                                                   ");
				query.append("   ehfm_disp_drug_mstr dmr,                                                                     ");
				query.append("   ehfm_disp_drug_mnfctr ddm,                                                                   ");
				query.append("   ehfm_disp_drug_dstrbtr ddd                                                                   ");
				query.append(" WHERE edt.disp_id    = dmr.disp_id                                                             ");
				query.append(" AND ddt.drug_type_id = dmr.drug_type_id                                                        ");
				query.append(" AND dm.drug_id       = dmr.drug_id                                                             ");
				query.append(" AND dmr.drug_code    = dda.drug_code                                                           ");
				query.append(" AND ddm.mnfctr_id    = dmr.mnfctr_id                                                           ");
				query.append(" AND ddd.dstrbtr_id   = dmr.dstrbtr_id                                                          ");
				query.append(" AND dmr.quantity     > 0  and dmr.ACTIVE_YN='Y'                                                                     ");
				query.append("    and dmr.DSTRBTR_ID = '"+distrbutr+"'                                                              ");
				if(searchType != null && "Exp".equalsIgnoreCase(searchType)){
				query.append("    and trunc(dmr.expiry_date) <TRUNC(SYSDATE)                                                         ");
				 if((fromDate != null && !"".equals(fromDate)) && (toDate != null && !"".equals(toDate))){
				 query.append("    and trunc(dmr.expiry_date) between to_Date('"+fromDate+"', 'DD/MM/YYYY') and                     ");
				 query.append("        to_Date('"+toDate+"', 'DD/MM/YYYY')                                                          ");
			     }
				}
				else if(searchType != null && "Avbl".equalsIgnoreCase(searchType)){
					query.append("    and trunc(dmr.expiry_date) >= TRUNC(SYSDATE)   	");
				}
				if(dispName != null && !"".equals(dispName))
				query.append("    and edt.disp_id = '"+dispName+"'                                                                   ");
				query.append(" group by edt.disp_name,                                                                        ");
				query.append(" ddt.drug_type_name,                                                                            ");
				query.append(" dm.drug_name,                                                                                  ");
				query.append(" ddm.mnfctr_name,                                                                               ");
				query.append(" ddd.dstrbtr_name,                                                                              ");
				query.append(" dmr.drug_code,                                                                                 ");
				query.append(" dmr.batch_no,                                                                                  ");
				query.append(" dmr.expiry_date,                                                                               ");
				query.append(" dmr.quantity                                                                                   ");
				query.append(" ORDER BY ddt.drug_type_name,                                                                   ");
				query.append("   dm.drug_name,  dmr.expiry_date                                                               ");

				
				
				expiredDrgList= genericDao.executeSQLQueryList(LabelBean.class, query.toString());
			}
			catch(Exception e){
				e.printStackTrace();
			}
			return expiredDrgList;
		}
		@Override
		public boolean submitRequestForRTV(HashMap drugparam) {
			boolean flag = false;
			List<LabelBean>drugList = new ArrayList<>();
			String reqId = null;
			 EhfmDispDrugMstr mstr =null;
			 String userId = null;
			 String dispId = null;
			 String remarks=null;
			if(drugparam.get("userId") != null){
				userId=(String)drugparam.get("userId");
			}
			if(drugparam.get("drugList") != null && ((List<LabelBean>)drugparam.get("drugList")).size() >0){
				drugList =(List<LabelBean>)drugparam.get("drugList");
			}
			if(drugparam.get("dispId") != null){
				dispId=(String)drugparam.get("dispId");
			}
			if(drugparam.get("remarks") != null){
				remarks=(String)drugparam.get("remarks");
			}
			try{
				String sequence1=getSequenceVal("DISP_DRUG_RETURN_SEQ");
			    reqId="RTV"+sequence1;
			    if(drugList != null && drugList.size()>0){
			    	for(LabelBean drg :drugList){
			    		mstr = genericDao.findById(EhfmDispDrugMstr.class, String.class, drg.getDrugCode());
			    		if(mstr != null){
			    		EhfDispDrgReturnVendor ehfDispDrgReturnVendor= new EhfDispDrgReturnVendor();
			    		EhfDispDrgReturnVendorId ehfDispDrgReturnVendorId = new EhfDispDrgReturnVendorId();
			    		ehfDispDrgReturnVendorId.setReturnRqstId(reqId);
			    		ehfDispDrgReturnVendorId.setDrugCode(drg.getDrugCode());
			    		ehfDispDrgReturnVendor.setId(ehfDispDrgReturnVendorId);
			    		ehfDispDrgReturnVendor.setDrugId(mstr.getDrugId());
			    		ehfDispDrgReturnVendor.setDrugTypeId(mstr.getDrugTypeId());
			    		ehfDispDrgReturnVendor.setBatchNo(mstr.getBatchNo());
			    		ehfDispDrgReturnVendor.setPrice(mstr.getPrice());
			    		ehfDispDrgReturnVendor.setQuantity(Long.parseLong(drg.getQUANTITY()));
			    		ehfDispDrgReturnVendor.setDstrbtrId(mstr.getDstrbtrId());
			    		ehfDispDrgReturnVendor.setMnfctrId(mstr.getMnfctrId());
			    		ehfDispDrgReturnVendor.setExpiryDate(mstr.getExpiryDate());
			    		ehfDispDrgReturnVendor.setReturnDate(new Date());
			    		ehfDispDrgReturnVendor.setDispId(dispId);
			    		ehfDispDrgReturnVendor.setStatus("Init");
			    		ehfDispDrgReturnVendor.setRemarks(remarks);
			    		ehfDispDrgReturnVendor.setCrtUsr(userId);
			    		ehfDispDrgReturnVendor.setCrtDate(new Date());
			    		Long updatedQuant = drg.getQuantity() - Long.parseLong(drg.getQUANTITY());
			    		
			    		
			    		EhfDispDrugMstrAudit audit=new EhfDispDrugMstrAudit();
						Long sno = Long.parseLong(getSequence("ehf_disp_drug_mstr_audit_seq"));
						audit.setSno(sno);
						audit.setPatientId(reqId);
						audit.setCaseId(reqId);
						audit.setDrugCode(drg.getDrugCode());
						audit.setAvailableQuant(updatedQuant);
						audit.setDeductedQuant(Long.parseLong(drg.getQUANTITY()));
						audit.setExistingQuant(mstr.getQuantity());
						audit.setCrtDate(new Date());
						audit.setCrtUsr(userId);
						
						mstr.setQuantity(updatedQuant);
			    		mstr.setLstUpdDate(new Date());
			    		mstr.setLstUpdUsr(userId);
						
			    		genericDao.save(ehfDispDrgReturnVendor);
			    		genericDao.save(mstr);
			    		genericDao.save(audit);
			    		flag=true;
			    		}
			    	}
			    }
			    
			}catch(Exception e){
				flag=false;
				e.printStackTrace();
			}
			return flag;
		}
		@Override
		public List<LabelBean> getDrugsInvoiceList(Map dataMap) {
			List<LabelBean> drgInvoiceList = new ArrayList<>();
			StringBuffer query = new StringBuffer();
			String fromDate = (String)dataMap.get("fromDate");
			String toDate = (String)dataMap.get("toDate");
			String dispName = (String)dataMap.get("dispName");
			String distrbutr =(String)dataMap.get("distrbutr");
			
			
			try{
				 query.append(" select TO_CHAR(SUBSTR(edt.disp_name, 6)) DISP_NAME,           ");
				 query.append("  TO_CHAR(ddd.dstrbtr_name)              AS DSTRBTRNAME,       ");
				 query.append("  TO_CHAR(dda.invoice_num)              AS INVOICENUMBER,      ");
				 query.append("  TO_CHAR(dda.invoice_dt,'DD-MM-RRRR')  AS ISSUEDATE ,          ");
				 query.append("  TO_CHAR(ddd.DSTRBTR_ID)               AS NATUREID            ");
				 query.append("  from EHFM_DISP_DRUG_MSTR ddm,                                ");
				 query.append("  EHFM_DISP_DRUG_AUDIT dda ,                                   ");
				 query.append("  ehfm_dispensary_dtls edt,                                    ");
				 query.append("  ehfm_disp_drug_dstrbtr ddd                                   ");
				 query.append("  where ddm.DRUG_CODE= dda.DRUG_CODE                           ");
				 query.append("  and ddm.DSTRBTR_ID= ddd.DSTRBTR_ID                           ");
				 query.append("  and ddm.DISP_ID= edt.DISP_ID                                 ");
				 query.append("  and ddm.QUANTITY >0 and ddm.ACTIVE_YN='Y'                    ");
				 query.append("  and ddm.disp_id ='"+dispName+"'                              ");
				 query.append("  and ddm.DSTRBTR_ID= '"+distrbutr+"'                          ");
				 if(fromDate != null && !"".equalsIgnoreCase(fromDate) && toDate != null && !"".equalsIgnoreCase(toDate)){
				  query.append("    and trunc(dda.invoice_dt) between to_Date('"+fromDate+"', 'DD/MM/YYYY') and                     ");
				  query.append("        to_Date('"+toDate+"', 'DD/MM/YYYY')                                                          ");	 
				 }
				 query.append("  group by edt.disp_name ,ddd.dstrbtr_name,                    ");
				 query.append("  dda.invoice_num ,dda.invoice_dt ,ddd.DSTRBTR_ID                             ");
				
				
				 drgInvoiceList= genericDao.executeSQLQueryList(LabelBean.class, query.toString());
			}
			catch(Exception e){
				e.printStackTrace();
			}
			return drgInvoiceList;
		}
		@Override
		public boolean submitCreditNoteRequest(HashMap drugparam) {
			boolean flag = false;
			List<LabelBean>drugList = new ArrayList<>();
			String reqId = null;
			 EhfmDispDrugMstr mstr =null;
			 String userId = null;
			 String dispId = null;
			 
			if(drugparam.get("userId") != null){
				userId=(String)drugparam.get("userId");
			}
			if(drugparam.get("drugList") != null && ((List<LabelBean>)drugparam.get("drugList")).size() >0){
				drugList =(List<LabelBean>)drugparam.get("drugList");
			}
			if(drugparam.get("dispId") != null){
				dispId=(String)drugparam.get("dispId");
			}
			
			try{
				String sequence1=getSequenceVal("DISP_CREDIT_NOTE_SEQ");
			    reqId="CN"+sequence1;
			    if(drugList != null && drugList.size()>0){
			    	for(LabelBean drg :drugList){
			    		
			    		EhfDispDrgCreditNote ehfDispDrgCreditNote = new EhfDispDrgCreditNote();
			    		String sno=getSequenceVal("DISP_CREDIT_NOTE_SNO");
			    		ehfDispDrgCreditNote.setSno(Long.parseLong(sno));
			    		ehfDispDrgCreditNote.setCreditRqstId(reqId);
			    		ehfDispDrgCreditNote.setPurchaseInvoiceNum(drg.getINVOICENUMBER());
			    		ehfDispDrgCreditNote.setDispId(dispId);
			    		ehfDispDrgCreditNote.setAmount(drg.getDrugPrice());
			    		ehfDispDrgCreditNote.setDstrbtrId(drg.getDSTRBTRNAME());
			    		ehfDispDrgCreditNote.setReturnInvoiceNum(drg.getISSUE_QUANT());
			    		if(drg.getISSUEDATE() != null && !"".equalsIgnoreCase(drg.getISSUEDATE()))
			    		ehfDispDrgCreditNote.setReturnInvoiceDt(new SimpleDateFormat("dd-MM-yyyy").parse(drg.getISSUEDATE()));
						ehfDispDrgCreditNote.setPurchaseInvoiceDt(drg.getInvDate());
						ehfDispDrgCreditNote.setCrtUsr(userId);
						ehfDispDrgCreditNote.setCrtDate(new Date());
						ehfDispDrgCreditNote.setLstUpdDate(new Date());
						ehfDispDrgCreditNote.setLstUpdUsr(userId);
			    		genericDao.save(ehfDispDrgCreditNote);
			    		
			    		flag=true;
			    		}
			    	
			    }
			    
			}catch(Exception e){
				flag=false;
				e.printStackTrace();
			}
			return flag;
		}
		
