		@Override
		public boolean saveManfctDrugDetailsNew(HashMap paramMap) {
			StringBuffer query=new StringBuffer();
			String manufacturerName = (String) paramMap.get("manufacturerName");
			String userId = (String) paramMap.get("userId");
			Date todayDate=new Date();
			boolean flag=false;
			
			try{
				if(manufacturerName!=null && !"".equalsIgnoreCase(manufacturerName))
				           {
								//Creating new Manufacuturer
								String mnfSequence=getSequenceVal("DISP_DRUG_MANUFACTURER_SEQ");
								String mnfctrId="MNF"+mnfSequence;
								EhfmDispDrugMnfctr mnfctr=new EhfmDispDrugMnfctr();
								mnfctr.setMnfctrId(mnfctrId);
								mnfctr.setMnfctrName(manufacturerName.toUpperCase());
								mnfctr.setCrtUsr(userId);
								mnfctr.setCrtDate(todayDate);
								genericDao.save(mnfctr);
								flag=true;
							}
							
			}
			catch(Exception e)
			{
				e.printStackTrace();
			}
			
			return flag;
		}
