		@Override
		public java.lang.String getDrugName(java.lang.String dispDrugID) {
			// TODO Auto-generated method stub
			String drugName="";
			try{
			
				StringBuffer query=new StringBuffer();
				query.append(" SELECT drug_name as VALUE FROM ehfm_disp_drug where drug_id= '"+dispDrugID+"' ");
				List<LabelBean> newBeanLst=genericDao.executeSQLQueryList(LabelBean.class, query.toString());
				if(newBeanLst != null && newBeanLst.size() >0 && newBeanLst.get(0)!=null)
				{
					drugName=newBeanLst.get(0).getVALUE();
				}
			}
			catch(Exception e)
			{
				e.printStackTrace();
			}
			
			return drugName;
		}
