	@Override
	public List<LabelBean> getOutStandingdrugs(String drugType,String drugName,String wc,String searchType,String drugDrill) 
			{
		List<LabelBean> osDrugList =new ArrayList<LabelBean>();
		StringBuffer query = new StringBuffer();
if(searchType != null && !"".equals(searchType) && ("-1".equalsIgnoreCase(searchType) || "AllNoBatch".equalsIgnoreCase(searchType)))
{

	query.append(" select ehfmdispdr2_.DRUG_TYPE_NAME as DRUGTYPE,                                      ");
	query.append("        ehfmdispdr1_.DRUG_NAME as DRUGNAME, ehfmdispdr1_.DRUG_ID as DRUGIDS,                                           ");
	if((wc!=null && !wc.trim().equalsIgnoreCase("")) || "Y".equalsIgnoreCase(drugDrill)){
		query.append("        substr(ehfmdispdr3_.DISP_name,                                                ");
		query.append("              instr(ehfmdispdr3_.DISP_name, '-') + 2) as WCNAME,                      ");
	}
	query.append("        to_char(nvl(sum(ehfmdispdr0_.QUANTITY),0)) as QUANTITY                                        ");
	query.append("   from EHFM_DISP_DRUG_MSTR ehfmdispdr0_,                                             ");
	query.append("        EHFM_DISP_DRUG      ehfmdispdr1_,                                             ");
	query.append("        EHFM_DISP_DRUG_TYPE ehfmdispdr2_                                            ");
	if((wc!=null && !wc.trim().equalsIgnoreCase("")) || "Y".equalsIgnoreCase(drugDrill))
		query.append("        ,ehfm_dispensary_dtls ehfmdispdr3_                                             ");
	query.append("  where ehfmdispdr0_.DRUG_ID = ehfmdispdr1_.DRUG_ID                                   ");
	query.append("    and ehfmdispdr0_.DRUG_TYPE_ID = ehfmdispdr2_.DRUG_TYPE_ID                         ");
	query.append("    and ehfmdispdr0_.ACTIVE_YN = 'Y'                                                  ");
	if((wc!=null && !wc.trim().equalsIgnoreCase("")) || "Y".equalsIgnoreCase(drugDrill)){
		query.append("    and ehfmdispdr3_.disp_id=ehfmdispdr0_.disp_id                                     ");
		if(wc!=null && !wc.trim().equalsIgnoreCase(""))
			query.append(" and ehfmdispdr0_.DISP_ID = '"+wc+"' ");
	}
	if(drugType!=null && !drugType.trim().equalsIgnoreCase("")){
		if("Y".equalsIgnoreCase(drugDrill))
			query.append("  and ehfmdispdr2_.DRUG_TYPE_NAME  = '"+drugType+"' ");
		else
			query.append(" and ehfmdispdr0_.DRUG_TYPE_ID = '"+drugType+"' ");
	}
	if(drugName!=null && !drugName.trim().equalsIgnoreCase("")){
		query.append(" and ehfmdispdr0_.DRUG_ID = '"+drugName+"' ");
	}
	if(searchType != null && !"".equals(searchType) && ("-1".equalsIgnoreCase(searchType))){
		query.append(" and ehfmdispdr0_.QUANTITY > 0");
		query.append(" and  trunc(ehfmdispdr0_.EXPIRY_DATE) >= trunc(sysdate) ");
	}
	                                                 
	query.append("  group by ehfmdispdr2_.DRUG_TYPE_NAME, ehfmdispdr1_.DRUG_NAME, ehfmdispdr1_.DRUG_ID ");
	if((wc!=null && !wc.trim().equalsIgnoreCase("")) || "Y".equalsIgnoreCase(drugDrill))
		query.append(" ,ehfmdispdr3_.DISP_name ");
	query.append("  order by ehfmdispdr1_.DRUG_NAME              ");
}else{
	query.append(" select ehfmdispdr2_.DRUG_TYPE_NAME as DRUGTYPE, ehfmdispdr1_.DRUG_NAME as DRUGNAME,to_char(ehfmdispdr5_.quat) as TOTALQUANTITY, to_char(ehfmdispdr0_.QUANTITY) as QUANTITY, ehfmdispdr3_.MNFCTR_NAME as MNFCTRNAME, ");
	query.append(" ehfmdispdr4_.DSTRBTR_NAME as DSTRBTRNAME, ehfmdispdr0_.BATCH_NO as BATCHNO, to_char(ehfmdispdr0_.EXPIRY_DATE, 'DD-MM-YYYY') as EXPDT, to_char(ehfmdispdr0_.price) as UNIT_PRICE, ehfmdispdr5_.invoice_num as INVOICE_NUM, ehfmdispdr0_.DRUG_CODE as DRUGCODE, substr( ehfmdispdr6_.DISP_name,instr(ehfmdispdr6_.DISP_name,'-')+2) as WCNAME ");
	query.append(" from EHFM_DISP_DRUG_MSTR    ehfmdispdr0_, EHFM_DISP_DRUG         ehfmdispdr1_, EHFM_DISP_DRUG_TYPE    ehfmdispdr2_, EHFM_DISP_DRUG_MNFCTR  ehfmdispdr3_, EHFM_DISP_DRUG_DSTRBTR ehfmdispdr4_, ");
	query.append(" (select  sum(quantity) quat,drug_code, wm_concat(invoice_num) invoice_num from ehfm_disp_drug_audit group by drug_code)   ehfmdispdr5_, ehfm_dispensary_dtls ehfmdispdr6_");
	query.append(" where ehfmdispdr0_.DRUG_ID = ehfmdispdr1_.DRUG_ID ");
	query.append(" and ehfmdispdr0_.DRUG_TYPE_ID = ehfmdispdr2_.DRUG_TYPE_ID ");
	query.append(" and ehfmdispdr0_.MNFCTR_ID = ehfmdispdr3_.MNFCTR_ID ");
	query.append(" and ehfmdispdr0_.DSTRBTR_ID = ehfmdispdr4_.DSTRBTR_ID ");
	query.append(" and ehfmdispdr5_.DRUG_CODE = ehfmdispdr0_.DRUG_CODE ");
	query.append(" and ehfmdispdr6_.DISP_ID =ehfmdispdr0_.DISP_ID ");
	query.append(" and ehfmdispdr0_.ACTIVE_YN = 'Y' ");
	
	if(wc!=null && !wc.trim().equalsIgnoreCase("")){
		query.append(" and ehfmdispdr0_.DISP_ID = '"+wc+"' ");
	}
	if(drugType!=null && !drugType.trim().equalsIgnoreCase("")){
		query.append(" and ehfmdispdr0_.DRUG_TYPE_ID = '"+drugType+"' ");
	}
	if(drugName!=null && !drugName.trim().equalsIgnoreCase("")){
		query.append(" and ehfmdispdr0_.DRUG_ID = '"+drugName+"' ");
	}
	if(searchType != null && !"".equals(searchType) && ("AvblBatch".equalsIgnoreCase(searchType))){
		query.append(" and ehfmdispdr0_.QUANTITY > 0");
		query.append(" and trunc(ehfmdispdr0_.EXPIRY_DATE) >= trunc(sysdate) ");
	}
	
	query.append(" order by ehfmdispdr1_.DRUG_NAME ");
	
}
		osDrugList = genericDao.executeSQLQueryList(LabelBean.class, query.toString());
		return osDrugList;
	}
