		public List<LabelBean> getExpdtRpt(String wc, String indNo) {
			List<LabelBean> expdtuplist =new ArrayList<LabelBean>();
			StringBuffer query = new StringBuffer();
			
			query.append("SELECT substr(edt.disp_name, 6)  disp_name	,");
			query.append("	ddt.drug_type_name   AS drug_type,");
			query.append("  dm.drug_name         AS drug_name,");
			query.append("  ddm.mnfctr_name      AS mnfctrname,");
			query.append("	ddd.dstrbtr_name     AS dstrbtrname,");
			query.append("	dmr.batch_no         AS batchno,");
			query.append("	to_char(dmr.expiry_date, 'dd/MM/yyyy' )     AS EXPDT,");
			query.append("	to_char(dmr.quantity)          AS quantity");
			
			query.append("	FROM");
			query.append("  ehfm_dispensary_dtls    edt,");
			query.append("  ehfm_disp_drug_type     ddt,");
			query.append("  ehfm_disp_drug          dm,");
			query.append("  ehfm_disp_drug_mstr     dmr,");
			query.append("  ehfm_disp_drug_mnfctr   ddm,");
			query.append("  ehfm_disp_drug_dstrbtr  ddd ");

			query.append("	WHERE ");
			query.append(" edt.disp_id = dmr.disp_id");
			query.append(" AND ddt.drug_type_id = dmr.drug_type_id");
			query.append(" AND dm.drug_id = dmr.drug_id");
			query.append(" AND ddm.mnfctr_id = dmr.mnfctr_id");
			query.append(" AND ddd.dstrbtr_id = dmr.dstrbtr_id");
			query.append(" AND dmr.quantity > 0");
			query.append(" AND dmr.active_yn = 'Y'");
		    query.append(" AND trunc(dmr.expiry_date) BETWEEN SYSDATE AND (SYSDATE+120)");


			if(wc!=null && !"".equalsIgnoreCase(wc) && !"-1".equalsIgnoreCase(wc)){
			query.append("AND edt.disp_id = 'DISP6'");
			}
			
			//query.append("	AND EDM.DSTRBTR_ID='?'");
			query.append(" ORDER BY disp_name,ddt.drug_type_name,dm.drug_name,dmr.expiry_date");
			
			expdtuplist = genericDao.executeSQLQueryList(LabelBean.class, query.toString());
			return expdtuplist;
		}
	
