	@Override
	public List<LabelBean> getindentPO(String wc, String indNo, String distributorId) {
		List<LabelBean> indentList=new ArrayList<LabelBean>();
		StringBuffer query = new StringBuffer();
		
		query.append("	SELECT EWI.INDENT_ID AS INDENT_NO,");
		query.append("	EWI.CRT_DT AS INDENT_DT,");
		query.append("	EDM.NEW_ITEM_ID AS ITEMID,");
		query.append("	EDD.DRUG_NAME AS DRUGNAME,");
		query.append("	EDD.DRUG_ID AS DRUGID,");
		query.append("	EDT.DRUG_TYPE_NAME AS DRUGTYPE,");
		query.append("	EDM.MANF_ID AS MNFCTRID,");
		query.append("	EDM.MANF_NAME AS MNFCTRNAME,");
		query.append("	EDM.VENDOR_ID  AS DISTRIBUTOR_ID,");
		query.append("	EDM.VENDOR_NAME  AS DISTRIBUTOR_NAME,");
		query.append("	EWI.INDENT_COUNT AS INDENT_COUNT,     ");
		query.append("	EWI.PO_ID AS PO_NO,  EWI.PO_ID1 AS PO_NO1,     ");
		query.append("	EWI.PO_DATE AS PO_DT,     ");
		query.append("	ED.DISP_NAME AS DISPNAME     ");
		query.append("  ,EDM.CR_NCR_DRUG_FLG AS CRITICAL_FLG  ");//Chandana - 9008 - Added this to get the critical flag
		query.append("	FROM");
		query.append("	EHF_WC_INDENT EWI,");
		query.append("	EHF_DISP_DRUG_MNF_DST_MPGG EDM,");
		query.append("	EHFM_DISP_DRUG EDD,");
		query.append("	EHFM_DISP_DRUG_TYPE EDT,");
		query.append("	EHFM_DISPENSARY_DTLS      ED");
		query.append("	WHERE ");
		query.append("	EWI.DRUG_CODE=EDM.DRUG_ID");
		query.append("	AND EWI.DRUG_CODE=EDD.DRUG_ID");
		query.append("	AND EDD.DRUG_TYPE_ID=EDT.DRUG_TYPE_ID");
		query.append("	AND EWI.DISP_ID = ED.DISP_ID");
		query.append("	AND EWI.STATUS='CD1415'");
		query.append("	AND EWI.ACTIVE_YN='N'");
		if(wc!=null && !"".equalsIgnoreCase(wc) && !"-1".equalsIgnoreCase(wc)){
		query.append("	AND EWI.DISP_ID='"+wc+"'");
		}
		if(indNo!=null && !"".equalsIgnoreCase(indNo)){
		if(!"----------Select-------------".equalsIgnoreCase(indNo))
		query.append("	AND EWI.INDENT_ID='"+indNo+"'");
		}
		if(distributorId!=null && !"".equalsIgnoreCase(distributorId) && !"-1".equalsIgnoreCase(distributorId)){
			query.append("	AND EDM.VENDOR_ID='"+distributorId+"'");
			}
		//query.append("	AND EDM.DSTRBTR_ID='?'");
		query.append("	ORDER BY CRITICAL_FLG DESC, EWI.PO_DATE DESC");//Chandana - 9008 - CRITICAL_FLG DESC, added this is the order by condition
		
		indentList = genericDao.executeSQLQueryList(LabelBean.class, query.toString());
		return indentList;
	}
	@Override
	public List<LabelBean> getstoreList(String wc, String indNo) {
		List<LabelBean> StoreList=new ArrayList<LabelBean>();
		StringBuffer query = new StringBuffer();
		
		query.append("	select distinct ewi.PO_ID         as PO_ID, ");
		query.append("	eddp.partial_full as LVL,");
		query.append("	ewi.DRUG_CODE     as ID,");
		query.append("	ed.drug_type_id  as DRUG_TYPE_ID,");
		query.append("	ewi.PO_DATE       as PO_DATE,");
		query.append("	ewi.INDENT_ID     as INDENT_ID,");
		query.append("	ewi.RATE_CONTRACT_PRICE       as DRUGPRICE,");
		query.append("	ewi.CRT_DT        as INDENT_DT,");
		query.append("	ewi.DRUG_NAME     as DRUG_NAME,");
		query.append("	ed.vendor_id     as DISTRIBUTOR_ID,");
		query.append("	eddp.mnfctr_id as MNFCTR_ID,");
		query.append("	ewi.DSTRBTR_NAME  as DISTRIBUTOR_NAME,");
		query.append("	ewi.MNFCTR_NAME  as MNFCTRNAME,");
		query.append("	ewi.INDENT_COUNT  as INDENT_COUNT,ewi.INDENT_COUNT_CONSTANT  as INDENT_COUNT_CONSTANT,");
		query.append("	ewi.IDEAL_STOCK   as IDEAL_STOCK,");
		query.append("	ewi.RECEIVED_QTY  as RECEIVED_QTY,");
		query.append("	ewi.DISP_ID       as DISP_ID");
		query.append("	from EHF_WC_INDENT          ewi,");
		query.append("	ehf_disp_drug_po       eddp,");
		query.append("	EHF_DISP_DRUG_MNF_DST_MPGG ed");
		query.append("	WHERE ewi.INDENT_COUNT != 0");
		query.append("	AND (ewi.STATUS = 'CD1416' or ewi.status = 'CD1418')");
		query.append("	AND ewi.PO_ID IS NOT NULL");
		query.append("	and eddp.partial_full != 'Cancelled'");
		query.append("	and eddp.po_id = ewi.po_id");
		query.append("	and ewi.item_id = ed.new_item_id and eddp.mnfctr_id=ed.manf_id");
		if(wc!=null && !"".equalsIgnoreCase(wc) && !"-1".equalsIgnoreCase(wc)){
		query.append("	AND DISP_ID='"+wc+"'");
		}
		if(indNo!=null && !"".equalsIgnoreCase(indNo)&& !"-1".equalsIgnoreCase(indNo)){
		if(!"----------Select-------------".equalsIgnoreCase(indNo))
		query.append("	AND ewi.PO_ID='"+indNo+"'");
		}
		//query.append("	AND EDM.DSTRBTR_ID='?'");
		query.append("	ORDER BY ewi.PO_ID");
		
		StoreList = genericDao.executeSQLQueryList(LabelBean.class, query.toString());
		return StoreList;
	}
