	@Override
	public List<LabelBean> getOnclickMnfPORpt(String mnfPoNo) {
		List<LabelBean> poList=new ArrayList<LabelBean>();
		StringBuffer query = new StringBuffer();
		
		query.append("	SELECT EWI.DRUG_NAME AS DRUGNAME,");
		query.append("	EWI.DRUG_ID AS DRUGID,     ");
		query.append("	EWI.MNFCTR_ID AS MNFCTRID,");
		query.append("	EWI.MNFCTR_NAME AS MNFCTRNAME,");
		query.append("	EWI.CRT_DT AS PO_DT,     ");
		query.append("	EWI.INDENT_COUNT AS INDENT_COUNT,");
		query.append("	EWI.INDENT_ID AS INDENT_ID,");
		query.append("	EWP.CRT_USR as EMPID,");
		query.append("	EU.FIRST_NAME || ' ' || EU.LAST_NAME as EMPNAME");
		query.append("	FROM EHF_DISP_DRUG_PO EWI, EHF_WC_INDENT EWP, EHFM_USERS EU");
		query.append("	WHERE ");
		query.append("EU.user_id=EWP.crt_usr AND ");
		query.append("EWP.PO_ID= EWI.PO_ID AND ");
		query.append("EWP.INDENT_ID= EWI.INDENT_ID AND ");
		query.append("EWP.DRUG_CODE= EWI.DRUG_ID ");
		if(mnfPoNo!=null && !"".equalsIgnoreCase(mnfPoNo) && !"-1".equalsIgnoreCase(mnfPoNo)){
		query.append("	AND  EWI.MNFCTR_PO_ID='"+mnfPoNo+"'");
		}
		query.append("	ORDER BY EWI.CRT_DT DESC");
		poList = genericDao.executeSQLQueryList(LabelBean.class, query.toString());
		return poList;
	}
