	@Override
	public List<LabelBean> getOnclickPORpt1(String poNo,String status,String lStrUserId,String drugId) {
		List<LabelBean> poList=new ArrayList<LabelBean>();
		StringBuffer query = new StringBuffer();
		
		query.append("select DISTINCT eddp.MNFCTR_PO_ID POID,ewi.po_id PO_ID, ewi.po_date PODATE,ewi.DSTRBTR_ID DSTRBTR_ID,ewi.dstrbtr_name DSTRBTRNAME,ewi.INDENT_ID INDENT_ID,ewi.STATUS STATUS, ");
		query.append("eddp.DRUG_ID DRUG_ID, ewi.drug_name DRUGNAME,eddp.DRUG_TYPE_NAME DRUG_TYPE_ID, ewi.drug_type DRUGTYPE,ewi.available_count AVL,ewi.ITEM_ID ITEMID, ");
		query.append("ewi.indent_count POQTY,ewi.indent_count_constant LVL,ewi.pending_indent PENIND,ewi.RATE_CONTRACT_PRICE RCP, ");
		query.append("ewi.MNFCTR_NAME MNFCTRNAME,ewi.MNFCTR_ID MNFCTR_ID ");
		if ("CD1420".equals(status)) {
            query.append(",ewivg.QUANTITY AS ISSUE_QUANT ");
        }
		query.append("from ehf_wc_indent ewi,ehf_dstrbtr_usr_mpg DUM,EHF_DISP_DRUG_PO eddp ");
		if ("CD1420".equals(status)) {
            query.append(", EHF_WC_INDENT_VNDR_GST ewivg ");
        }
		query.append("WHERE EWI.DSTRBTR_ID =DUM.DSTRBTR_ID AND ewi.PO_ID = eddp.PO_ID AND ewi.ITEM_ID = eddp.ITEM_ID AND ewi.po_id IS NOT NULL ");
		
		if(poNo!=null && !"".equalsIgnoreCase(poNo) && !"-1".equalsIgnoreCase(poNo)){
		query.append("and eddp.MNFCTR_PO_ID='"+poNo+"' ");
		}
		if(drugId!=null && !"".equalsIgnoreCase(drugId) && !"-1".equalsIgnoreCase(drugId)){
			query.append("and eddp.DRUG_ID='"+drugId+"' ");
			}
//		if (status != null && !"".equals(status)) {
//		    query.append("AND ewi.STATUS = '" + status + "' ");   
//		}
		if ("CD1416".equals(status)) {
            query.append(" AND ewi.STATUS = 'CD1416' ");
        }
		if ("CD1420".equals(status)) {
			query.append(" AND ewivg.STATUS IN ('CD1420','CD1422','CD1421') ");
            query.append(" AND ewivg.QUANTITY_FLG = 'N' and ewivg.VNDR_UPLD_FLG = 'N' AND ewivg.item_id = eddp.item_id and ewivg.mnfctr_po_id = eddp.mnfctr_po_id ");
        }
		query.append("AND DUM.USER_ID = '"+lStrUserId+"' ");
		poList = genericDao.executeSQLQueryList(LabelBean.class, query.toString());
		//System.out.println("poList:::"+query.toString());
		for (LabelBean lb : poList) {
			String submittedQty = getSubmittedQtyFromGst(lb.getPOID(), lb.getITEMID());
		    lb.setRECQTY(submittedQty);    
		}
		
		return poList;
	}
