	@Override
	public List<LabelBean> getPoItemsForPdf(String poNo,String itemIds) {

	    StringBuffer query = new StringBuffer();

	    query.append("SELECT DISTINCT EWIVGA.ITEM_ID AS ITEMID, ewivga.PO_ID AS POID,ewivga.PO_DATE AS PODATE, ewivga.DRUG_NAME AS DRUGNAME, ewivga.DRUG_TYPE_ID AS DRUGTYPE, ");
	    query.append("ewivga.BATCH_NO AS BATCHNO, ewivga.EXPIRY_DATE AS DOSAGE,ewivga.QUANTITY AS QUANTITY, ewivga.RATE_CONTRACT_PRICE AS RC_PRICE, ");
	    query.append("ewivga.GST_SLAB AS CONST, ewivga.INVOICE_AMOUNT AS NEXTVAL,ewivga.TOTAL_AMOUNT AS DIFF,EWI.MNFCTR_NAME MNFCTRNAME,ewivga.INVOICE_NO AS INVOICENO, ");
	    query.append("ewivga.INVOICE_DATE AS INVOICE_NUM FROM EHF_WC_INDENT_VNDR_GST_AUDIT ewivga,EHF_WC_INDENT EWI WHERE ewi.PO_ID = EWIVGA.PO_ID ");
	    query.append("AND ewi.ITEM_ID = EWIVGA.ITEM_ID AND ewivga.STATUS IN ('CD1425') AND ewivga.MNFCTR_PO_ID = '"+poNo+"' ");
	    if (itemIds != null && !itemIds.trim().isEmpty()) {
	    	itemIds = itemIds.replace(" ", "");
	    	String formattedItemIds = "'" + itemIds.replace(",", "','") + "'";

	        query.append(" AND ewivga.ITEM_ID IN (" + formattedItemIds + ") ");
	    }
	   query.append("AND ewivga.ACT_ORDER = (SELECT MAX(a2.ACT_ORDER) FROM EHF_WC_INDENT_VNDR_GST_AUDIT a2 ");
	    query.append("WHERE a2.PO_ID = ewivga.PO_ID AND a2.ITEM_ID = ewivga.ITEM_ID ) ");
	    System.out.println("> Query = "+ query.toString());
	    //System.out.println("POList size = " + POList.size());
	    return genericDao.executeSQLQueryList(LabelBean.class, query.toString());
	}
