	@Override
	@Transactional
	public boolean addNewMnfNDist1(HashMap storedrugList, String lstrUserId) {

	    StringBuffer query  = new StringBuffer();
	    StringBuffer query1 = new StringBuffer();
	    StringBuffer query2 = new StringBuffer();

	    Date todayDate = new Date();
	    boolean flag = false;

	    try {
	    	SessionFactory factory = hibernateTemplate.getSessionFactory();
		    Session session = factory.openSession();
	        query.append("select id.dispId as ID from EhfmDispUsrMpg where id.userId='"+lstrUserId+"' ");

	        List<LabelBean> dispList = genericDao.executeHQLQueryList(LabelBean.class, query.toString());

	        if (dispList == null || dispList.isEmpty() || dispList.get(0).getID() == null) {
	            return false;
	        }

	        String dispCode = dispList.get(0).getID();

	       
	        List<HashMap<String, Object>> storePOList = (List<HashMap<String, Object>>) storedrugList.get("storePOList");

	        if (storePOList == null || storePOList.isEmpty()) {
	            return false;
	        }

	        for (HashMap<String, Object> record : storePOList) {

	            String drugId       = record.get("drugId").toString();
	            String drugType     = record.get("drugTypeId").toString();
	            String batchNo      = record.get("batchNo").toString();
	            String mfdId        = record.get("mnfctrId").toString();
	            String poQty = record.get("poQty").toString();
	            String dstId        = record.get("dstrbtrId").toString();
	            String itemId       = record.get("itemId").toString();
	            String internalStatus      = record.get("internalStatus").toString();
	            String poNo  = record.get("poId").toString();
	            String indentId = record.get("indentId").toString();
	            Double drugPrice    = Double.parseDouble(record.get("rcPrice").toString());
	            Long quantity       = Long.parseLong(record.get("quantity").toString());
	            Long receivedQty = Long.parseLong(record.get("receivedQty").toString());
	            Long currentReceiptQty = Long.parseLong(record.get("currentReceiptQty").toString());
	            
	            Long totalReceived = receivedQty + currentReceiptQty;
	            Long pendingCount = quantity - totalReceived;
	            String status;
 
	            String invoiceNo    = record.get("invoiceNo").toString();

	            Date invoiceDate = null;
	            Date expiryDate  = null;

	            SimpleDateFormat sdf = new SimpleDateFormat("dd-MM-yyyy");
	            sdf.setLenient(false);

	            if (record.get("invoiceDate") != null && !"".equals(record.get("invoiceDate"))) {
	                invoiceDate = sdf.parse(record.get("invoiceDate").toString());
	            }

	            if (record.get("expiryDate") != null && !"".equals(record.get("expiryDate"))) {
	                expiryDate = sdf.parse(record.get("expiryDate").toString());
	            }
	            
	            StringBuffer cumulativeQtyQuery = new StringBuffer();
	            cumulativeQtyQuery.append("SELECT NVL(RECEIVED_QTY, 0) AS ID FROM ehf_wc_indent ");
	            cumulativeQtyQuery.append("WHERE INDENT_ID = '" + indentId + "' AND ITEM_ID = '" + itemId + "' ");

	            List cumulativeList = genericDao.executeSQLQueryList(LabelBean.class, cumulativeQtyQuery.toString());

	            String previouslyReceivedQty = "0";
	            if (cumulativeList != null && !cumulativeList.isEmpty()
	                    && cumulativeList.get(0) != null
	                    && ((LabelBean) cumulativeList.get(0)).getID() != null) {
	                previouslyReceivedQty = ((LabelBean) cumulativeList.get(0)).getID().toString();
	            }

	            // Add current receivedQty to previously received for cumulative total
	            long cumulativeTotalReceived = Long.parseLong(previouslyReceivedQty) + currentReceiptQty;

	            if (String.valueOf(cumulativeTotalReceived).equals(poQty)) {
	                status        = "CD1427";
	                internalStatus = "PO Fully Received by Store Keeper";
	            } else if (cumulativeTotalReceived == quantity) {
	                status        = "CD1421";
	                internalStatus = "Ack By Store Keeper";
	            } else if (cumulativeTotalReceived  < quantity) {
	                status        = "CD1422";
	                internalStatus = "Partially received by Store keeper";
	            } else {
	                status = null;
	            }
	            
	            StringBuffer seqIdQuery = new StringBuffer();
	            seqIdQuery.append("SELECT SEQ_ID AS COUNT FROM Ehf_Wc_Indent_Vndr_Gst_Audit ");
	            seqIdQuery.append("WHERE ITEM_ID = '"+itemId+"' AND INDENT_ID = '"+indentId+"' ORDER BY ACT_ORDER DESC ");
	            List<LabelBean> seqIdList = genericDao.executeSQLQueryList(LabelBean.class, seqIdQuery.toString());
	            
	            long seqId = 1; // default value
	            if (seqIdList != null && !seqIdList.isEmpty() && seqIdList.get(0) != null && seqIdList.get(0).getCOUNT() != null) {
	                seqId = seqIdList.get(0).getCOUNT().longValue();
	            }

	            int check = 0;

	            query1.setLength(0);
	            query1.append("select drugCode as ID from EhfmDispDrugMstr where drugId='"+drugId+"' and drugTypeId='"+drugType+"' ");
	            query1.append("and mnfctrId='"+mfdId+"' and dstrbtrId='"+dstId+"' and upper(batchNo)=upper('"+batchNo+"') ");
	            query1.append("and dispId='"+dispCode+"'");

	            List<LabelBean> drugList = genericDao.executeHQLQueryList(LabelBean.class, query1.toString());

	            if (drugList != null && !drugList.isEmpty() && drugList.get(0).getID() != null) {

	                check = 1;
	                String drugCode = drugList.get(0).getID();

	                EhfmDispDrugMstr mstr = genericDao.findById(EhfmDispDrugMstr.class, String.class, drugCode);

	                if (mstr != null) {
	                	
	                	long existingMasterQty = mstr.getQuantity();
	                	Long deltaQty = currentReceiptQty;
	                    
	                    if (deltaQty <= 0) {
	                        deltaQty = receivedQty;
	                    }
	                   
	                    mstr.setQuantity(existingMasterQty + deltaQty);
	                    mstr.setBatchNo(batchNo.toUpperCase());
	                    mstr.setLstUpdUsr(lstrUserId);
	                    mstr.setLstUpdDate(todayDate);
	                    mstr.setItemId(itemId);
		                mstr.setPoId(poNo);
		                mstr.setPendingIndent(pendingCount);

	                    query2.setLength(0);
	                    query2.append("select count(id.actOrder) as COUNT from EhfmDispDrugAudit where id.drugCode='"+drugCode+"' ");

	                    List<LabelBean> countList = genericDao.executeHQLQueryList(LabelBean.class, query2.toString());

	                    long actOrder = 1L;

	                    if (countList != null && !countList.isEmpty()
	                            && countList.get(0) != null
	                            && countList.get(0).getCOUNT() != null) {

	                        actOrder = countList.get(0).getCOUNT().longValue() + 1L;
	                    }


	                    EhfmDispDrugAudit audit = new EhfmDispDrugAudit();
	                    audit.setId(new EhfmDispDrugAuditId(drugCode, actOrder));
	                    audit.setPharmacistId(lstrUserId);
	                    audit.setSeqId(seqId);
	                    audit.setQuantity(String.valueOf(deltaQty));
	                    audit.setInvoiceNumber(invoiceNo);
	                    audit.setInvoiceDate(invoiceDate);
	                    audit.setCrtDate(todayDate);
	                    audit.setLstUpdDt(todayDate);
		                audit.setLstUpdUsr(lstrUserId);
	                    audit.setDispCode(dispCode);
	                    audit.setPoId(poNo);
	                    
	                    genericDao.save(audit);
	                    genericDao.save(mstr);
	                    flag = true;
	                }
	            }

	            if (check == 0) {

	                String drugCode = "DRG" + getSequenceVal("DISP_DRUG_CODE_SEQ");

	                EhfmDispDrugMstr mstr = new EhfmDispDrugMstr();
	                mstr.setDrugCode(drugCode);
	                mstr.setDrugId(drugId);
	                mstr.setDrugTypeId(drugType);
	                mstr.setMnfctrId(mfdId);
	                mstr.setDstrbtrId(dstId);
	                mstr.setPrice(drugPrice);
	                mstr.setBatchNo(batchNo.toUpperCase());
	                //mstr.setQuantity(receivedQty);
	                mstr.setQuantity(currentReceiptQty);
	                mstr.setDispId(dispCode);
	                mstr.setExpiryDate(expiryDate);
	                mstr.setActiveYN("Y");
	                mstr.setCrtUsr(lstrUserId);
	                mstr.setCrtDate(todayDate);
	                mstr.setLstUpdUsr(lstrUserId);
	                mstr.setLstUpdDate(todayDate);
	                mstr.setItemId(itemId);
	                mstr.setPoId(poNo);
	                mstr.setPendingIndent(pendingCount);

	                EhfmDispDrugAudit audit = new EhfmDispDrugAudit();
	                audit.setId(new EhfmDispDrugAuditId(drugCode, 1L));
	                audit.setPharmacistId(lstrUserId);
	                audit.setSeqId(seqId);
	                audit.setQuantity(currentReceiptQty.toString());
	                audit.setInvoiceNumber(invoiceNo);
	                audit.setInvoiceDate(invoiceDate);
	                audit.setCrtDate(todayDate);
	                audit.setLstUpdDt(todayDate);
	                audit.setLstUpdUsr(lstrUserId);
	                audit.setDispCode(dispCode);

	                genericDao.save(audit);
	                genericDao.save(mstr);
	                flag = true;
	            }
	            
	            try
				{
				StringBuffer indentQuery=new StringBuffer();
				indentQuery.append("UPDATE EhfWcIndentVndrGstAudit SET STATUS = ?,INTERNALSTATUS = ? WHERE SEQ_ID = ? ");
			
	            session.createQuery(indentQuery.toString())
	             .setParameter(0, status)
	             .setParameter(1, internalStatus)  
	             .setParameter(2, seqId)    
	            .executeUpdate();
	    
				}
				catch(Exception e)
				{
					e.printStackTrace();
				}

	            try
				{
				StringBuffer indentQuery=new StringBuffer();
				if ("CD1427".equals(status)) {
                    indentQuery.append("UPDATE EhfWcIndent ");
                    indentQuery.append("SET RECEIVED_QTY =  ?, STATUS = ?, INDENT_STATUS = 'Y', ACTIVE_YN = 'R' ");
                    indentQuery.append("WHERE INDENT_ID = ? AND ITEM_ID = ? ");
                } else {
                    indentQuery.append("UPDATE EhfWcIndent ");
                    indentQuery.append("SET RECEIVED_QTY = ?, STATUS = ?, INDENT_STATUS = 'Y' ");
                    indentQuery.append("WHERE INDENT_ID = ? AND ITEM_ID = ? ");
                }
			
	            session.createQuery(indentQuery.toString())
	            .setParameter(0, cumulativeTotalReceived)
	             .setParameter(1, status)
	            .setParameter(2, indentId)  
	             .setParameter(3, itemId)    
	            .executeUpdate();
	    
				}
				catch(Exception e)
				{
					e.printStackTrace();
				}
	        }
	       

	    } catch (Exception e) {
	        e.printStackTrace();
	        return false;
	    }

	    return flag;
	}

						
