	@Override
	public List<LabelBean> getpoNotRsv(String dispname) {
		StringBuffer query = new StringBuffer();
		List<LabelBean> indentPOList = new ArrayList<LabelBean>();
		try {

			query.append("	select distinct(edd.disp_name) DISPNAME,ewi.po_date PODATE, ewi.drug_code DRUGCODE, ewi.dstrbtr_name DSTRBTRNAME,ewi.mnfctr_name MNFCTRNAME, ewi.po_id POID");
			query.append("	from ehf_wc_indent ewi,ehfm_dispensary_dtls edd,ehf_disp_drug_po edp where ewi.disp_id=edd.disp_id");
			
			query.append("  and ewi.po_date  <= (sysdate-45) ");
			if(dispname!=null &&  !"-1".equalsIgnoreCase(dispname)){
				query.append("  and ewi.disp_id='"+ dispname + "'   ");
			}
			
			query.append(" and ewi.drug_code=edp.drug_id and ewi.po_id is not null and edp.partial_full!='Cancelled'  order by ewi.po_date ");
			
			indentPOList = genericDao.executeSQLQueryList(LabelBean.class,query.toString());
		} catch (Exception e) {
			e.printStackTrace();
		}
		return indentPOList;
	}
