	public List<PreauthVO> getConsentData(String wc, String lStrCaseID){
		List<PreauthVO> res = new ArrayList<PreauthVO>();
		StringBuffer querymain = new StringBuffer();
		querymain.append("	select distinct mnfctr_po_id MNFCTRID from ehf_disp_drug_po  ");
		if(lStrCaseID!=null && !"".equalsIgnoreCase(lStrCaseID) && !"-1".equalsIgnoreCase(lStrCaseID)){
			querymain.append(" where  PO_ID='"+lStrCaseID+"'");
			}
		querymain.append("	order by mnfctr_po_id" );
	      List<PreauthVO> preauthListmain= genericDao.executeSQLQueryList(PreauthVO.class,querymain.toString());

		for(PreauthVO ls : preauthListmain){
      StringBuffer query = new StringBuffer();
      query.append("	SELECT EWI.INDENT_ID AS INDENT_NO,");
		query.append("	to_char(EWI.CRT_DT,'dd.mm.yyyy') AS INDENTDT,");
		query.append("	EDM.NEW_ITEM_ID AS ITEMID,");
		query.append("	eddp.mnfctr_po_id as MNFCTRID,");
		query.append("	EDD.DRUG_NAME AS DRUGNAME,");
		query.append("	EDD.DRUG_ID AS DRUGID,");
		query.append("	EDT.DRUG_TYPE_NAME AS DRUGTYPE,");
		query.append("	EDM.MANF_ID AS MNFCTRID,");
		query.append("	EDM.NAME_AS_PER_RC AS MNFCTRNAME,");
		query.append("	EDM.VENDOR_ID AS DISTRIBUTOR_ID,");
		query.append("	EDM.VENDOR_NAME AS DISTRIBUTOR_NAME,");
		query.append("	EWI.INDENT_COUNT AS INDENT_COUNT,     ");
		query.append("	EWI.PO_ID AS PO_NO,     ");
		query.append("	to_char(EWI.PO_DATE,'dd.mm.yyyy') AS PODT,     ");
		query.append("	EWI.INDENT_VALUE AS RC_VALUE, EWI.RATE_CONTRACT_PRICE AS RC_PRICE,    ");
		query.append("	ED.DISP_CITY AS DISPNAME ,info.address \"hospAddress\", info.contact_no NEWCONTACTNO,ED.DP_CD WCNAME,fin_year(sysdate) FIN_YEAR ");
		query.append("	FROM");
		query.append("	EHF_WC_INDENT EWI,");
		query.append("	EHF_DISP_DRUG_MNF_DST_MPGG EDM,");
		query.append("	EHFM_DISP_DRUG EDD,");
		query.append("	EHFM_DISP_DRUG_TYPE EDT,");
		query.append("	EHFM_DISPENSARY_DTLS      ED, ehf_disp_drug_po eddp, ehfm_wellness_center_info info ");
		query.append("	WHERE ");
		query.append("	EWI.DRUG_CODE=EDM.DRUG_ID");
		query.append("	AND EWI.DRUG_CODE=EDD.DRUG_ID");
		query.append("	AND EDD.DRUG_TYPE_ID=EDT.DRUG_TYPE_ID and ewi.disp_id = info.disp_id");
		query.append("	AND EWI.DISP_ID = ED.DISP_ID and eddp.drug_id = ewi.drug_code  and ewi.po_id = eddp.po_id");
		query.append("	AND EWI.STATUS='CD1416'");
		query.append("	AND EWI.ACTIVE_YN='N'");
		if(wc!=null && !"".equalsIgnoreCase(wc) && !"-1".equalsIgnoreCase(wc)){
		query.append("	AND EWI.DISP_ID='"+wc+"'");
		}
		if(lStrCaseID!=null && !"".equalsIgnoreCase(lStrCaseID) && !"-1".equalsIgnoreCase(lStrCaseID)){
		query.append("	AND eddp.mnfctr_po_id='"+ls.getMNFCTRID()+"'");
		}
           
      
      System.out.println(">>> Query = "+ query.toString());
      List<PreauthVO> preauthList= genericDao.executeSQLQueryList(PreauthVO.class,query.toString());
      PreauthVO p = new PreauthVO();
      p.setDispnsryList(preauthList);
		
		res.add(p);
		}

     return res;
  }
