			query.append(" a.invoice_num as INVOICENO,");
			query.append(" TO_CHAR(A.Crt_Date, 'DD-MM-YYYY') as CRTDATE,");
			query.append(" sum(to_number(a.quantity)) as PACKAGE_AMOUNT,");
			query.append(" SUM(To_number(B.quantity)) AS AVAILABLE_QUANTITY,");
			
			query.append(" to_char(ed.disp_name) DISPNAME, ");
			query.append(" ed.disp_id AS DISP_ID  ");
			query.append(" from ehfm_disp_drug_audit   a, ");
			query.append(" ehfm_disp_drug_mstr    b, ");
			query.append(" ehfm_disp_drug         c, ");
			query.append(" ehfm_disp_drug_type    d, ");
			query.append(" ehfm_disp_drug_mnfctr  e, ");
			query.append(" ehfm_disp_drug_dstrbtr f,ehfm_dispensary_dtls ed ");
			query.append(" WHERE a.drug_code = b.drug_code ");
			query.append(" and b.drug_type_id = c.drug_type_id ");
