			query.append(" and a.disp_code = '"+center+"' ");
			query.append(" and trunc(A.crt_date) between to_date('"+fromDate+"', 'DD/MM/YYYY') and to_date('"+toDate+"', 'DD/MM/YYYY')");
			query.append(" and c.drug_name like '%"+drugname.toUpperCase()+"%' ");
