	// Get Drugs From Inventory
		public Map<String, Object> getDrugInventoryMaster(){					
			Map<String, Object> response = new HashMap<String, Object>();
			
			StringBuffer queryDrugType = new StringBuffer();
			StringBuffer queryDrugName = new StringBuffer();
			StringBuffer queryManftName = new StringBuffer();
			StringBuffer queryDispName = new StringBuffer();
			List<LabelBeanInventory> drugTypes = new ArrayList<LabelBeanInventory>();
			List<LabelBeanInventory> drugNames = new ArrayList<LabelBeanInventory>();
			List<LabelBeanInventory> mangftNames = new ArrayList<LabelBeanInventory>();
			List<LabelBeanInventory> distriNames = new ArrayList<LabelBeanInventory>();
			try
			{
				queryDrugType.append("SELECT DRUG_TYPE_ID,DRUG_TYPE_NAME FROM EHFM_DISP_DRUG_TYPE ORDER BY DRUG_TYPE_NAME ASC");
				queryDrugName.append("SELECT DRUG_ID,DRUG_NAME FROM EHFM_DISP_DRUG ORDER BY DRUG_NAME ASC");
				queryManftName.append("SELECT MNFCTR_ID,MNFCTR_NAME FROM EHFM_DISP_DRUG_MNFCTR ORDER BY MNFCTR_NAME ASC");
				queryDispName.append("SELECT DSTRBTR_ID,DSTRBTR_NAME FROM EHFM_DISP_DRUG_DSTRBTR ORDER BY DSTRBTR_NAME ASC");
										
				drugTypes = genericDao.executeSQLQueryList(LabelBeanInventory.class, queryDrugType.toString());
				drugNames = genericDao.executeSQLQueryList(LabelBeanInventory.class, queryDrugName.toString());
				mangftNames = genericDao.executeSQLQueryList(LabelBeanInventory.class, queryManftName.toString());
				distriNames = genericDao.executeSQLQueryList(LabelBeanInventory.class, queryDispName.toString());
			}
			catch(Exception e){
				GLOGGER.error("ERROR:: " +e.getMessage());
			}
			
			response.put("status", "success");
			response.put("drugTypes", drugTypes);
			response.put("drugNames", drugNames);
			response.put("mangftNames", mangftNames);
			response.put("distriNames", distriNames);
			response.put("message", "Record fetched successfully");
			
			return response;
		}
