	//Chandana - 8443 - Implemented below method for abha numbers, using abha number getting the main card number either journalist or emp or pensioner
	@Override
	public String getCardDtlsForAbhaSearch(String cardNo){
		List<LabelBean> submitList =null;
		String cardType = null;
		String cardNum = null;
		try
		{						  
			StringBuffer query = new StringBuffer();
			query.append(" SELECT EF.EHF_CARD_NO ID, decode(user_role,'CD3022','E','P') VALUE FROM ASRIM_USERS AU,EHF_ENROLLMENT EE,EHF_ENROLLMENT_FAMILY EF WHERE AU.LOGIN_NAME=EE.EMP_CODE");
			query.append(" AND EE.ENROLL_PRNT_ID=EF.ENROLL_PRNT_ID AND AU.ACTIVE_YN='Y' AND AU.SCHEME='CD202' AND EF.ABHA_ID ='"+cardNo+"' ");
			submitList = genericDao.executeSQLQueryList(LabelBean.class, query.toString());
			if(submitList != null && !submitList.isEmpty()){
				cardNum = submitList.get(0).getID();
	            cardType = submitList.get(0).getVALUE();
			}
			else{
				query = new StringBuffer();
				query.append(" SELECT JOURNAL_CARD_NO ID FROM EHF_JRNLST_FAMILY WHERE ABHA_ID ='"+cardNo+"' ");
				submitList = genericDao.executeSQLQueryList(LabelBean.class, query.toString());
				if(submitList != null && !submitList.isEmpty()){
					cardNum = submitList.get(0).getID();
					cardType = "J";
				}
			}
		}
		catch(Exception e)
		{
			GLOGGER.error("Exception Occurred in retrieveAisCardDetails() in PatientDaoImpl class."+e.getMessage());
			e.printStackTrace();
		}
		if(cardNum != null || cardType !=null)
			return cardNum + "~" +cardType;
		else
			return null;
	}
	//Tejasri- CR-8812 Wellness Centers - Attendance dashboard to Wellness Centre Admin
	@Override
	public List<LabelBean> wellnessCentreList(String dispId) {
		List<LabelBean> list=new ArrayList<LabelBean>();
		StringBuffer query=new StringBuffer();

	    try {
	        query.append("SELECT ");
	        query.append("    DD.DISP_ID AS WFTYPE, ");
	        query.append("    DD.DISP_NAME AS PENIND, ");
	        query.append("    COUNT(DISTINCT EU.USER_ID) AS DIFF, ");
	        query.append("    COUNT(DISTINCT EF1.USER_ID) AS SNO, ");
	        query.append("    COUNT(DISTINCT EF2.USER_ID) AS QTY, ");
	        query.append("    ROUND((COUNT(DECODE(EF1.CHECK_IN, 'CI', 1, NULL)) / COUNT(DISTINCT EU.USER_ID)) * 100, 2) || '%' AS LVL, ");
	        query.append("    ROUND((COUNT(DECODE(EF2.CHECK_OUT, 'CO', 1, NULL)) / COUNT(DISTINCT EU.USER_ID)) * 100, 2) || '%' AS INVNO ");
	        query.append("FROM ");
	        query.append("    EHFM_USERS EU, ");
	        query.append("    EHFM_DESIGNATION ED, ");
	        query.append("    EHFM_DISP_USR_MPG EDU, ");
	        query.append("    EHFM_DISPENSARY_DTLS DD, ");
	        query.append("    (SELECT * FROM EHS_FRS_ATTENDANCE ");
	        query.append("        WHERE CHECK_IN = 'CI' ");
	        query.append("          AND TRUNC(CHECK_IN_TIME) = TRUNC(SYSDATE)) EF1, ");
	        query.append("    (SELECT * FROM EHS_FRS_ATTENDANCE ");
	        query.append("        WHERE CHECK_OUT = 'CO' ");
	        query.append("          AND TRUNC(CHECK_OUT_TIME) = TRUNC(SYSDATE)) EF2 ");
	        query.append("WHERE ");
	        query.append("    EU.DSGN_ID = ED.DSGN_ID ");
	        query.append("    AND EDU.DISP_ID = DD.DISP_ID ");
	        query.append("    AND EU.USER_ID = EDU.USER_ID ");
	        query.append("    AND EU.USER_ID = EF1.USER_ID(+) ");
	        query.append("    AND EU.USER_ID = EF2.USER_ID(+) ");
	        query.append("    AND EU.service_flg = 'Y' ");
	        query.append("    AND EDU.GRP_ID = 'GP827' ");
	      //pravalika added condition for wellness center when logged in to that
	        if (dispId != null && !dispId.trim().isEmpty()) {
	            query.append(" AND DD.DISP_ID = '").append(dispId).append("' ");
	        }
	        
	        query.append("GROUP BY ");
	        query.append("    DD.DISP_ID, ");
	        query.append("    DD.DISP_NAME ");
	        query.append("ORDER BY ");
	        query.append("    2 ");
		    list=genericDao.executeSQLQueryList(LabelBean.class, query.toString());
		}
		catch(Exception e)
		{
			e.printStackTrace();
		}
		return list;
	}
