		        query.append("    COUNT(DISTINCT EU.USER_ID) AS DIFF, ");
		        query.append("    COUNT(DISTINCT EF1.USER_ID) AS SNO, ");
		        query.append("    COUNT(DISTINCT EF2.USER_ID) AS QTY, ");
