		        query.append("    ROUND((COUNT(DECODE(EF2.CHECK_OUT, 'CO', 1, NULL)) / COUNT(DISTINCT EU.USER_ID)) * 100, 2) || '%' AS INVNO ");
		        query.append("FROM ");
