		        query.append("          AND TRUNC(CHECK_IN_TIME) =  TRUNC(TO_DATE(?,'DD/MM/YYYY'))) EF1, ");
		        query.append("    (SELECT * FROM EHS_FRS_ATTENDANCE ");
